{
  "name": "AssetTrack Pro - Gestão de Ativos TI",
  "description": "Uma plataforma completa para gestão de ativos de TI, controle de inventário, solicitações de equipamentos e dashboards analíticos para diretoria.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AssetType = 
  | 'Desktop' 
  | 'Notebook' 
  | 'Mouse' 
  | 'Cabo' 
  | 'Monitor' 
  | 'Teclado' 
  | 'Headset' 
  | 'Suporte Notebook';

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface Asset {
  id: string;
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; // Employee ID
  qrCode: string;
  createdAt: string;
}

export interface Employee {
  id: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
}

export interface User extends Employee {
  permissions: 'Admin' | 'RH' | 'TI' | 'Diretoria';
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId: string;
  items: AssetType[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Entregue' | 'Cancelado';
  createdAt: string;
}

import { GoogleGenAI } from "@google/genai";
import { Asset } from "../types";

export const generateAssetReportSummary = async (assets: Asset[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const assetSummary = assets.map(a => `${a.type} ${a.brand} (${a.status})`).join(', ');
  const prompt = `Como um consultor sênior de TI, analise este inventário de ativos e forneça um resumo executivo de 3 frases sobre a saúde da frota: ${assetSummary}`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar o resumo automático.";
  } catch (error) {
    console.error("Erro no Gemini:", error);
    return "Erro ao carregar insights da IA.";
  }
};

