import React, { useEffect, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell 
} from 'recharts';
import { 
  ShieldCheck, 
  Activity, 
  AlertTriangle, 
  Layers,
  Sparkles
} from 'lucide-react';
import { Asset } from '../types';
import { generateAssetReportSummary } from '../services/geminiService';

interface DashboardProps {
  assets: Asset[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#6366f1'];

const Dashboard: React.FC<DashboardProps> = ({ assets }) => {
  const [aiInsight, setAiInsight] = useState<string>("Gerando insights inteligentes...");

  useEffect(() => {
    generateAssetReportSummary(assets).then(setAiInsight);
  }, [assets]);

  const stats = [
    { label: 'Total Ativos', value: assets.length, icon: Layers, color: 'text-blue-600', bg: 'bg-blue-100' },
    { label: 'Em Uso', value: assets.filter(a => a.status === 'Em Uso').length, icon: ShieldCheck, color: 'text-emerald-600', bg: 'bg-emerald-100' },
    { label: 'Em Manutenção', value: assets.filter(a => a.status === 'Manutenção').length, icon: Activity, color: 'text-amber-600', bg: 'bg-amber-100' },
    { label: 'Baixados', value: assets.filter(a => a.status === 'Baixado').length, icon: AlertTriangle, color: 'text-rose-600', bg: 'bg-rose-100' },
  ];

  const chartData = [
    { name: 'Desktop', qty: assets.filter(a => a.type === 'Desktop').length },
    { name: 'Notebook', qty: assets.filter(a => a.type === 'Notebook').length },
    { name: 'Monitor', qty: assets.filter(a => a.type === 'Monitor').length },
    { name: 'Outros', qty: assets.filter(a => !['Desktop', 'Notebook', 'Monitor'].includes(a.type)).length },
  ];

  const statusData = [
    { name: 'Disponível', value: assets.filter(a => a.status === 'Disponível').length },
    { name: 'Em Uso', value: assets.filter(a => a.status === 'Em Uso').length },
    { name: 'Manutenção', value: assets.filter(a => a.status === 'Manutenção').length },
    { name: 'Pendente Doc', value: assets.filter(a => a.status === 'Pendente Documentos').length },
  ];

  return (
    <div className="space-y-8">
      {/* AI Insight Card */}
      <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-6 rounded-3xl text-white shadow-xl shadow-blue-200 relative overflow-hidden">
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-3">
            <Sparkles className="w-6 h-6 text-blue-200" />
            <h3 className="font-bold text-lg">Insights de IA (Gemini)</h3>
          </div>
          <p className="text-blue-50 leading-relaxed max-w-3xl">
            {aiInsight}
          </p>
        </div>
        <div className="absolute top-[-20%] right-[-10%] w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex items-center justify-between mb-4">
              <div className={`${stat.bg} ${stat.color} p-3 rounded-2xl`}>
                <stat.icon className="w-6 h-6" />
              </div>
              <span className="text-2xl font-bold text-slate-800">{stat.value}</span>
            </div>
            <p className="text-sm font-medium text-slate-500">{stat.label}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Distribuicao por Tipo */}
        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Ativos por Categoria</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="qty" fill="#3b82f6" radius={[6, 6, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Status Distribuição */}
        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Status dos Ativos</h3>
          <div className="h-72 flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                   contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="flex flex-col gap-2 ml-4">
              {statusData.map((entry, idx) => (
                <div key={idx} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[idx % COLORS.length]}} />
                  <span className="text-xs font-medium text-slate-600">{entry.name}: {entry.value}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

