    if (!selectedAsset) return;
    const updated = { ...selectedAsset, ...updates };
    setSelectedAsset(updated);
    onUpdate(updated);
  };

  const handleAddPhoto = () => {
    // Simulating photo addition
    const newPhotoUrl = `https://picsum.photos/400/300?random=${Math.random()}`;
    if (selectedAsset) {
      handleUpdateDetail({ photos: [...selectedAsset.photos, newPhotoUrl] });
    }
  };

  const handleRemovePhoto = (index: number) => {
    if (selectedAsset) {
      const newPhotos = selectedAsset.photos.filter((_, i) => i !== index);
      handleUpdateDetail({ photos: newPhotos });
    }
  };

  const handlePrintLabel = () => {
    setIsPrinting(true);
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
    }, 500);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;
    return matchesSearch && matchesType;
  });

  const getAssignedEmployee = (id?: string) => employees.find(e => e.id === id);

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por modelo, marca ou ID..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          <select 
            className="bg-white border border-slate-200 px-4 py-3 rounded-2xl text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none"
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
          >
            <option value="all">Todos Tipos</option>
            {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
          <button 
            onClick={() => setShowForm(true)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-2xl font-bold transition-all shadow-lg shadow-blue-200 ml-auto sm:ml-0"
          >
            <Plus className="w-5 h-5" />
            <span>Novo Ativo</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Ativo / ID</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Tipo</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Marca/Modelo</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-center">Fotos</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredAssets.map((asset) => (
                <tr 
                  key={asset.id} 
                  onClick={() => setSelectedAsset(asset)}
                  className="hover:bg-blue-50/50 transition-colors cursor-pointer group"
                >
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-800 group-hover:text-blue-700">{asset.id}</span>
                      <span className="text-xs text-slate-400">Desde {asset.createdAt}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-bold">{asset.type}</span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex flex-col">
                      <span className="font-medium text-slate-800">{asset.brand}</span>
                      <span className="text-sm text-slate-500">{asset.model}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-center">
                    <div className="flex justify-center">
                      {asset.photos.length > 0 ? (
                        <div className="flex -space-x-2">
                          {asset.photos.map((p, i) => (
                            <img key={i} src={p} className="w-8 h-8 rounded-lg border-2 border-white object-cover" />
                          ))}
                        </div>
                      ) : (
                        <div className="flex items-center gap-1 text-amber-500">
                           <Camera className="w-4 h-4" />
                           <span className="text-[10px] font-bold">Pendente</span>
                        </div>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      asset.status === 'Disponível' ? 'bg-emerald-100 text-emerald-600' :
                      asset.status === 'Em Uso' ? 'bg-blue-100 text-blue-600' :
                      asset.status === 'Manutenção' ? 'bg-amber-100 text-amber-600' :
                      'bg-rose-100 text-rose-600'
                    }`}>
                      {asset.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right">
                    <div className="flex items-center justify-end gap-2" onClick={(e) => e.stopPropagation()}>
                       <button 
                        onClick={() => { setSelectedAsset(asset); handlePrintLabel(); }} 
                        className="p-2 text-slate-400 hover:text-blue-600 transition-colors" 
                        title="Gerar Etiqueta"
                      >
                         <QrCode className="w-5 h-5" />
                       </button>
                       <button onClick={() => onRemove(asset.id)} className="p-2 text-slate-400 hover:text-rose-600 transition-colors" title="Remover">
                         <Trash2 className="w-5 h-5" />
                       </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredAssets.length === 0 && (
            <div className="p-12 text-center text-slate-400 flex flex-col items-center">
              <Package className="w-12 h-12 mb-4 opacity-20" />
              <p>Nenhum ativo encontrado para esta busca.</p>
            </div>
          )}
        </div>
      </div>

      {/* Asset Details Slide-over Panel */}
      {selectedAsset && (
        <div className="fixed inset-0 z-[70] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setSelectedAsset(null)} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-slide-in-right">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-slate-800">Detalhes do Ativo</h3>
                <p className="text-sm text-slate-500">{selectedAsset.id}</p>
              </div>
              <button onClick={() => setSelectedAsset(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {/* Top Summary */}
              <div className="flex items-start gap-6">
                <div className="w-24 h-24 bg-slate-100 rounded-3xl flex items-center justify-center text-slate-400 shrink-0 overflow-hidden relative group">
                  {selectedAsset.photos[0] ? (
                    <img src={selectedAsset.photos[0]} className="w-full h-full object-cover" />
                  ) : (
                    <Camera className="w-8 h-8" />
                  )}
                  <button 
                    onClick={handleAddPhoto}
                    className="absolute inset-0 bg-black/40 text-white opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
                  >
                    <Camera className="w-6 h-6" />
                  </button>
                </div>
                <div className="space-y-1">
                  <span className="px-3 py-1 bg-blue-100 text-blue-600 rounded-full text-[10px] font-black uppercase tracking-wider">{selectedAsset.type}</span>
                  <h4 className="text-2xl font-bold text-slate-900">{selectedAsset.brand} {selectedAsset.model}</h4>
                  <select 
                    className={`block w-full mt-1 border-none bg-transparent font-bold text-xs p-0 focus:ring-0 ${
                      selectedAsset.status === 'Disponível' ? 'text-emerald-600' :
                      selectedAsset.status === 'Em Uso' ? 'text-blue-600' : 'text-amber-600'
                    }`}
                    value={selectedAsset.status}
                    onChange={(e) => handleUpdateDetail({ status: e.target.value as AssetStatus })}
                  >
                    <option value="Disponível">Disponível</option>
                    <option value="Em Uso">Em Uso</option>
                    <option value="Manutenção">Manutenção</option>
                    <option value="Baixado">Baixado</option>
                    <option value="Pendente Documentos">Pendente Doc</option>
                  </select>
                </div>
              </div>

              {/* Technical Specs */}
              <div className="grid grid-cols-2 gap-4">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-3">
                  <Cpu className="w-5 h-5 text-slate-400" />
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Processador</p>
                    <input 
                      className="text-sm font-bold text-slate-700 bg-transparent border-none p-0 focus:ring-0 w-full" 
                      value={selectedAsset.processor || ''}
                      onChange={(e) => handleUpdateDetail({ processor: e.target.value })}
                      placeholder="N/A"
                    />
                  </div>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100 flex items-center gap-3">
                  <Database className="w-5 h-5 text-slate-400" />
                  <div>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Memória RAM</p>
                    <input 
                      className="text-sm font-bold text-slate-700 bg-transparent border-none p-0 focus:ring-0 w-full" 
                      value={selectedAsset.ram || ''}
                      onChange={(e) => handleUpdateDetail({ ram: e.target.value })}
                      placeholder="N/A"
                    />
                  </div>
                </div>
                {/* Outros campos de specs poderiam ser editáveis similarmente */}
              </div>

              {/* Photos Gallery */}
              <div>
                <div className="flex justify-between items-center mb-3">
                  <h5 className="text-sm font-bold text-slate-700 flex items-center gap-2">
                    <Camera className="w-4 h-4" /> Galeria de Fotos
                  </h5>
                  <button 
                    onClick={handleAddPhoto}
                    className="text-blue-600 text-xs font-bold hover:underline flex items-center gap-1"
                  >
                    <Plus className="w-3 h-3" /> Adicionar Foto
                  </button>
                </div>
                <div className="grid grid-cols-4 gap-2">
                  {selectedAsset.photos.length > 0 ? (
                    selectedAsset.photos.map((p, i) => (
                      <div key={i} className="group aspect-square bg-slate-100 rounded-xl overflow-hidden relative">
                        <img src={p} className="w-full h-full object-cover" />
                        <button 
                          onClick={() => handleRemovePhoto(i)}
                          className="absolute top-1 right-1 bg-rose-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Trash2 className="w-3 h-3" />
                        </button>
                      </div>
                    ))
                  ) : (
                    <div className="col-span-4 p-8 border-2 border-dashed border-slate-200 rounded-2xl text-center">
                      <p className="text-xs text-slate-400">Nenhuma foto cadastrada para este ativo.</p>
                    </div>
                  )}
                </div>
              </div>

              {/* History & Assignment */}
              <div className="space-y-4">
                <div className="bg-slate-900 rounded-3xl p-6 text-white relative overflow-hidden group">
                  <div className="relative z-10 flex justify-between items-center">
                    <div className="space-y-1">
                      <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Identificação QR</p>
                      <p className="text-lg font-mono font-bold">{selectedAsset.qrCode}</p>
                    </div>
                    <button 
                      onClick={handlePrintLabel}
                      className="bg-white p-2 rounded-xl hover:scale-105 transition-transform"
                    >
                       <QrCode className="text-slate-900 w-12 h-12" />
                    </button>
                  </div>
                  <div className="absolute bottom-[-20%] left-[-10%] w-32 h-32 bg-blue-500/20 rounded-full blur-2xl" />
                </div>

                <div className="p-6 border border-slate-200 rounded-3xl space-y-4">
                   <div className="flex items-center justify-between">
                     <h5 className="text-sm font-bold text-slate-700">Responsável Atual</h5>
                     <Calendar className="w-4 h-4 text-slate-400" />
                   </div>

                   <div className="space-y-4">
                     {selectedAsset.assignedTo ? (
                       <div className="flex items-center justify-between">
                         <div className="flex items-center gap-3">
                           <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold">
                             <User className="w-5 h-5" />
                           </div>
                           <div>
                             <p className="text-sm font-bold text-slate-800">
                               {getAssignedEmployee(selectedAsset.assignedTo)?.name || `ID: ${selectedAsset.assignedTo}`}
                             </p>
                             <p className="text-xs text-slate-500">
                               {getAssignedEmployee(selectedAsset.assignedTo)?.sector}
                             </p>
                           </div>
                         </div>
                         <button 
                           onClick={() => handleUpdateDetail({ assignedTo: undefined, status: 'Disponível' })}
                           className="text-rose-500 p-2 hover:bg-rose-50 rounded-xl transition-colors"
                           title="Remover Atribuição"
                         >
                           <UserMinus className="w-5 h-5" />
                         </button>
                       </div>
                     ) : (
                       <div className="text-center py-2 bg-slate-50 rounded-2xl">
                         <p className="text-xs text-slate-500 mb-3">Este item está <strong>Disponível</strong> em estoque.</p>
                       </div>
                     )}

                     <div>
                       <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Alterar / Atribuir para:</label>
                       <select 
                         className="w-full bg-white border border-slate-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none"
                         value={selectedAsset.assignedTo || ''}
                         onChange={(e) => handleUpdateDetail({ assignedTo: e.target.value, status: 'Em Uso' })}
                       >
                         <option value="">Nenhum (Em estoque)</option>
                         {employees.map(emp => (
                           <option key={emp.id} value={emp.id}>{emp.name} ({emp.sector})</option>
                         ))}
                       </select>
                     </div>
                   </div>
                </div>
              </div>

              <div className="space-y-3">
                 <h5 className="text-sm font-bold text-slate-700">Observações Gerais</h5>
                 <textarea 
                   className="w-full text-sm text-slate-600 leading-relaxed italic bg-amber-50 p-4 rounded-2xl border border-amber-100 outline-none focus:ring-1 focus:ring-amber-300 resize-none"
                   rows={3}
                   value={selectedAsset.observations || ''}
                   onChange={(e) => handleUpdateDetail({ observations: e.target.value })}
                   placeholder="Adicione observações técnicas..."
                 />
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex gap-3">
               <button 
                onClick={handlePrintLabel}
                className="flex-1 bg-white border border-slate-200 py-3 rounded-2xl font-bold text-slate-700 flex items-center justify-center gap-2 hover:bg-slate-100 transition-all shadow-sm"
               >
                 <Printer className="w-4 h-4" />
                 {isPrinting ? 'Gerando...' : 'Etiqueta'}
               </button>
               <button 
                onClick={() => setSelectedAsset(null)}
                className="flex-1 bg-blue-600 text-white py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
               >
                 Salvar e Fechar
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Form Overlay (Cadastro) */}
      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">Cadastrar Novo Equipamento</h3>
              <button onClick={() => setShowForm(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-500" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Tipo de Equipamento</label>
                  <select 
                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={newAsset.type}
                    onChange={(e) => setNewAsset({...newAsset, type: e.target.value as AssetType})}
                    required
                  >
                    {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Marca</label>
                  <input 
                    type="text" 
                    placeholder="Ex: Dell, HP, Apple" 
                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={newAsset.brand || ''}
                    onChange={(e) => setNewAsset({...newAsset, brand: e.target.value})}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Modelo</label>
                  <input 
                    type="text" 
                    placeholder="Ex: Latitude 5420" 
                    className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={newAsset.model || ''}
                    onChange={(e) => setNewAsset({...newAsset, model: e.target.value})}
                    required
                  />
                </div>

                {(newAsset.type === 'Desktop' || newAsset.type === 'Notebook') && (
                  <>
                    <div className="space-y-2">
                      <label className="text-sm font-bold text-slate-700">Memória RAM</label>
                      <input 
                        type="text" 
                        placeholder="Ex: 16GB" 
                        className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={newAsset.ram || ''}
                        onChange={(e) => setNewAsset({...newAsset, ram: e.target.value})}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-sm font-bold text-slate-700">Armazenamento (Memória Física)</label>
                      <input 
                        type="text" 
                        placeholder="Ex: 512GB SSD" 
                        className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={newAsset.storage || ''}
                        onChange={(e) => setNewAsset({...newAsset, storage: e.target.value})}
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-sm font-bold text-slate-700">Processador</label>
                      <input 
                        type="text" 
                        placeholder="Ex: Intel Core i7" 
                        className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={newAsset.processor || ''}
                        onChange={(e) => setNewAsset({...newAsset, processor: e.target.value})}
                      />
                    </div>
                  </>
                )}

                {newAsset.type === 'Notebook' && (
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-slate-700">Tamanho da Tela</label>
                    <input 
                      type="text" 
                      placeholder="Ex: 14 Polegadas" 
                      className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                      value={newAsset.screenSize || ''}
                      onChange={(e) => setNewAsset({...newAsset, screenSize: e.target.value})}
                    />
                  </div>
                )}
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Observações (Danos ou Marcas de Uso)</label>
                <textarea 
                  rows={3}
                  className="w-full p-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                  placeholder="Descreva o estado físico atual..."
                  value={newAsset.observations || ''}
                  onChange={(e) => setNewAsset({...newAsset, observations: e.target.value})}
                />
              </div>

              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                  <Camera className="w-4 h-4" /> Fotos do Equipamento (Frente, Verso, Lateral L, Lateral R)
                </label>
                <div className="flex gap-4">
                  {[1,2,3,4].map(i => (
                    <div key={i} className="flex-1 aspect-square bg-slate-100 rounded-2xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center text-slate-400 hover:text-blue-500 hover:border-blue-300 transition-all cursor-pointer">
                      <Plus className="w-6 h-6" />
                      <span className="text-[10px] font-bold">Foto {i}</span>
                    </div>
                  ))}
                </div>
                <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3">
                  <AlertCircle className="w-5 h-5 text-amber-500 shrink-0" />
                  <p className="text-xs text-amber-700 leading-relaxed">
                    A inclusão de fotos é obrigatória para a validação final. Ativos sem foto ficarão com status <strong>"Pendente Documentos"</strong>.
                  </p>
                </div>
              </div>

              <div className="flex justify-end gap-3 pt-4">
                <button 
                  type="button"
                  onClick={() => setShowForm(false)}
                  className="px-6 py-3 rounded-2xl text-slate-600 font-bold hover:bg-slate-100 transition-colors"
                >
                  Cancelar
                </button>
                <button 
                  type="submit"
                  className="px-10 py-3 rounded-2xl bg-blue-600 hover:bg-blue-700 text-white font-bold transition-all shadow-lg shadow-blue-200"
                >
                  Salvar Ativo
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes slide-in-right {
          from { transform: translateX(100%); }
          to { transform: translateX(0); }
        }
        .animate-slide-in-right {
          animation: slide-in-right 0.3s ease-out;
        }
        @media print {
          body * { visibility: hidden; }
          .fixed.inset-0.z-\[70\] .bg-white { visibility: visible; position: absolute; left: 0; top: 0; width: 100%; height: auto; }
          .fixed.inset-0.z-\[70\] .bg-white * { visibility: visible; }
          .fixed.inset-0.z-\[70\] .bg-white button, .fixed.inset-0.z-\[70\] .bg-white .flex-1.overflow-y-auto { display: none; }
          .fixed.inset-0.z-\[70\] .bg-white .bg-slate-900 { display: block !important; border: 2px solid black; color: black; background: white !important; }
        }
      `}</style>
    </div>
  );
};

