import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import Auth from './components/Auth';
import { MOCK_ASSETS, MOCK_EMPLOYEES } from './constants';
import { Asset, Employee, EquipmentRequest } from './types';
import { Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [requests, setRequests] = useState<EquipmentRequest[]>([
    {
      id: 'REQ-1',
      requesterId: '2',
      employeeId: '1',
      items: ['Notebook', 'Mouse', 'Monitor'],
      status: 'Pendente',
      createdAt: '2024-03-20'
    }
  ]);

  const handleAddAsset = (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      id: `AST-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${Math.random().toString(36).substr(2, 9)}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleUpdateAsset = (updatedAsset: Asset) => {
    setAssets(assets.map(a => a.id === updatedAsset.id ? updatedAsset : a));
  };

  const handleAddEmployee = (empData: Omit<Employee, 'id'>) => {
    const newEmp: Employee = {
      ...empData,
      id: String(employees.length + 1)
    };
    setEmployees([newEmp, ...employees]);
  };

  const handleAddRequest = (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const newReq: EquipmentRequest = {
      ...reqData,
      id: `REQ-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      status: 'Pendente',
      createdAt: new Date().toLocaleDateString('pt-BR')
    };
    setRequests([newReq, ...requests]);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} />;
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={(id) => setAssets(assets.filter(a => a.id !== id))} 
          />
        );
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      case 'requests':
        return <RequestsManager requests={requests} employees={employees} onAddRequest={handleAddRequest} />;
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'inventory-check':
        return (
          <div className="flex flex-col items-center justify-center py-20 text-center space-y-4">
            <div className="w-20 h-20 bg-blue-100 rounded-full flex items-center justify-center text-blue-600">
              <Package className="w-10 h-10" />
            </div>
            <h3 className="text-2xl font-bold text-slate-800">Verificação Semestral de Inventário</h3>
            <p className="text-slate-500 max-w-md">
              A próxima auditoria geral de ativos está programada para <strong>Junho de 2024</strong>. 
              Nesta etapa, validaremos desgaste, mau uso e presença física dos itens.
            </p>
            <button className="bg-slate-800 text-white px-8 py-3 rounded-2xl font-bold">Iniciar Pré-Auditoria</button>
          </div>
        );
      default:
        return <Dashboard assets={assets} />;
    }
  };

  if (!isAuthenticated) {
    return <Auth onLogin={() => setIsAuthenticated(true)} />;
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Printer, 
  FileDown, 
  FileText, 
  Search, 
  CheckSquare, 
  Square, 
  QrCode, 
  Download,
  AlertCircle,
  ExternalLink
} from 'lucide-react';
import { Asset } from '../types';

interface PrintManagerProps {
  assets: Asset[];
}

const PrintManager: React.FC<PrintManagerProps> = ({ assets }) => {
  const [selectedAssetIds, setSelectedAssetIds] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [exporting, setExporting] = useState<string | null>(null);

  const filteredAssets = useMemo(() => {
    return assets.filter(a => 
      a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
      a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      a.brand.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [assets, searchTerm]);

  const toggleSelection = (id: string) => {
    setSelectedAssetIds(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const toggleAll = () => {
    if (selectedAssetIds.length === filteredAssets.length) {
      setSelectedAssetIds([]);
    } else {
      setSelectedAssetIds(filteredAssets.map(a => a.id));
    }
  };

  const handleExportTxt = () => {
    setExporting('TXT');
    const selectedAssets = assets.filter(a => selectedAssetIds.includes(a.id));
    const content = selectedAssets.map(a => (
      `==============================\n` +
      `ID: ${a.id}\n` +
      `TIPO: ${a.type}\n` +
      `MARCA: ${a.brand}\n` +
      `MODELO: ${a.model}\n` +
      `QR CODE: ${a.qrCode}\n` +
      `STATUS: ${a.status}\n` +
      `DATA: ${new Date().toLocaleDateString('pt-BR')}\n` +
      `==============================`
    )).join('\n\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `etiquetas_${new Date().getTime()}.txt`;
    link.click();

    setTimeout(() => {
      setExporting(null);
      URL.revokeObjectURL(url);
    }, 1500);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleExportPdfSimulation = () => {
    setExporting('PDF');
    // Simulation of PDF generation
    setTimeout(() => {
      setExporting(null);
      alert('PDF gerado com sucesso para ' + selectedAssetIds.length + ' etiquetas.');
    }, 2000);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Filtrar por ID ou Modelo..." 
            className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center gap-2">
          <button 
            disabled={selectedAssetIds.length === 0}
            onClick={handleExportTxt}
            className={`flex items-center gap-2 px-4 py-3 rounded-2xl font-bold transition-all border ${
              selectedAssetIds.length > 0 ? 'bg-white text-slate-700 hover:bg-slate-50 border-slate-200' : 'bg-slate-100 text-slate-400 border-transparent cursor-not-allowed'
            }`}
          >
            <FileText className="w-5 h-5" />
            <span>TXT</span>
          </button>
          <button 
            disabled={selectedAssetIds.length === 0}
            onClick={handleExportPdfSimulation}
            className={`flex items-center gap-2 px-4 py-3 rounded-2xl font-bold transition-all border ${
              selectedAssetIds.length > 0 ? 'bg-white text-slate-700 hover:bg-slate-50 border-slate-200' : 'bg-slate-100 text-slate-400 border-transparent cursor-not-allowed'
            }`}
          >
            <FileDown className="w-5 h-5" />
            <span>PDF</span>
          </button>
          <button 
            disabled={selectedAssetIds.length === 0}
            onClick={handlePrint}
            className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-bold transition-all shadow-lg ${
              selectedAssetIds.length > 0 ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-blue-200' : 'bg-slate-300 text-white cursor-not-allowed'
            }`}
          >
            <Printer className="w-5 h-5" />
            <span>Imprimir Selecionados</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* List Section */}
        <div className="lg:col-span-2 bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden flex flex-col h-[600px]">
          <div className="p-4 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <button onClick={toggleAll} className="p-2 hover:bg-slate-200 rounded-xl transition-colors">
                {selectedAssetIds.length === filteredAssets.length && filteredAssets.length > 0 ? (
                  <CheckSquare className="w-6 h-6 text-blue-600" />
                ) : (
                  <Square className="w-6 h-6 text-slate-300" />
                )}
              </button>
              <span className="text-sm font-bold text-slate-700">
                {selectedAssetIds.length} selecionados de {filteredAssets.length}
              </span>
            </div>
            <p className="text-xs text-slate-400 italic">Selecione para gerar lote de impressão</p>
          </div>

          <div className="flex-1 overflow-y-auto">
            <table className="w-full text-left border-collapse">
              <tbody className="divide-y divide-slate-100">
                {filteredAssets.map((asset) => (
                  <tr 
                    key={asset.id} 
                    onClick={() => toggleSelection(asset.id)}
                    className={`hover:bg-blue-50/30 transition-colors cursor-pointer ${selectedAssetIds.includes(asset.id) ? 'bg-blue-50/50' : ''}`}
                  >
                    <td className="px-6 py-4 w-12">
                       {selectedAssetIds.includes(asset.id) ? (
                         <CheckSquare className="w-5 h-5 text-blue-600" />
                       ) : (
                         <Square className="w-5 h-5 text-slate-200" />
                       )}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="font-bold text-slate-800">{asset.id}</span>
                        <span className="text-xs text-slate-400">{asset.type}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="font-medium text-slate-700">{asset.brand}</span>
                        <span className="text-xs text-slate-500">{asset.model}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                       <span className={`px-3 py-1 rounded-full text-[10px] font-bold ${
                         asset.status === 'Disponível' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'
                       }`}>
                         {asset.status}
                       </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filteredAssets.length === 0 && (
              <div className="p-12 text-center text-slate-400 flex flex-col items-center">
                <AlertCircle className="w-12 h-12 mb-4 opacity-20" />
                <p>Nenhum ativo disponível para seleção.</p>
              </div>
            )}
          </div>
        </div>

        {/* Preview Section */}
        <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-xl h-[600px] flex flex-col sticky top-24 print:static print:bg-white print:text-black print:shadow-none print:p-0 print:h-auto print:w-full">
           <div className="flex items-center gap-2 mb-8 print:hidden">
              <QrCode className="w-6 h-6 text-blue-400" />
              <h4 className="font-bold text-lg">Visualização da Etiqueta</h4>
           </div>

           {selectedAssetIds.length > 0 ? (
             <div className="flex-1 flex flex-col items-center justify-center space-y-8 print:space-y-12">
                <div className="bg-white p-4 rounded-3xl shadow-2xl shadow-blue-500/10 print:shadow-none print:border-2 print:border-black">
                   <div className="border-[1.5px] border-slate-900 p-2 rounded-2xl flex flex-col items-center gap-4">
                      <QrCode className="w-32 h-32 text-slate-900" />
                      <div className="w-full h-[1px] bg-slate-200" />
                      <div className="text-center">
                        <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest leading-none mb-1 print:text-black">Patrimônio AssetTrack</p>
                        <p className="text-2xl font-mono font-black text-slate-900 tracking-tighter leading-none">
                          {assets.find(a => a.id === selectedAssetIds[0])?.id}
                        </p>
                      </div>
                   </div>
                </div>

                <div className="text-center space-y-2 print:hidden">
                   <p className="text-sm text-slate-400 font-medium">Exibindo exemplo da 1ª etiqueta do lote.</p>
                   <p className="text-xs text-slate-500">Formato padrão: 40mm x 40mm (Térmica)</p>
                </div>

                {exporting && (
                  <div className="bg-blue-500/20 border border-blue-500/30 p-4 rounded-2xl flex items-center gap-3 animate-pulse print:hidden">
                    <Download className="w-5 h-5 text-blue-400" />
                    <span className="text-sm font-bold text-blue-100 tracking-tight">Gerando arquivo {exporting}...</span>
                  </div>
                )}
             </div>
           ) : (
             <div className="flex-1 flex flex-col items-center justify-center text-center opacity-30">
                <Printer className="w-16 h-16 mb-4" />
                <p className="font-medium text-slate-300">Selecione um ou mais ativos para pré-visualizar a impressão.</p>
             </div>
           )}

           <div className="mt-auto pt-6 border-t border-slate-800 space-y-4 print:hidden">
              <div className="flex items-center gap-2 text-xs text-slate-400">
                <AlertCircle className="w-4 h-4" />
                <span>Recomendamos papel fosco para melhor leitura do QR</span>
              </div>
              <button 
                onClick={() => window.open('https://ai.google.dev/gemini-api/docs/billing', '_blank')}
                className="w-full flex items-center justify-center gap-2 text-xs text-slate-500 hover:text-white transition-colors py-2"
              >
                <ExternalLink className="w-3 h-3" />
                Instruções de Configuração da Impressora
              </button>
           </div>
        </div>
      </div>

      {/* Hidden container for full batch printing */}
      <div id="print-area" className="hidden print:block print:bg-white print:p-0">
        {assets.filter(a => selectedAssetIds.includes(a.id)).map(a => (
          <div key={a.id} className="page-break-after-always flex flex-col items-center justify-center border-2 border-black p-4 m-4 w-[4cm] h-[4cm] mx-auto text-black">
             <QrCode className="w-24 h-24 mb-2" />
             <p className="text-[8px] font-bold uppercase">Patrimônio AssetTrack</p>
             <p className="text-lg font-mono font-black">{a.id}</p>
          </div>
        ))}
      </div>

      <style>{`
        @media print {
          body * { visibility: hidden; }
          #print-area, #print-area * { visibility: visible; }
          #print-area { position: absolute; left: 0; top: 0; width: 100%; }
          .page-break-after-always { page-break-after: always; }
          @page { margin: 0; }
        }
      `}</style>
    </div>
  );
};

export default PrintManager;

import React, { useState } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import Auth from './components/Auth';
import { MOCK_ASSETS, MOCK_EMPLOYEES } from './constants';
import { Asset, Employee, EquipmentRequest } from './types';
import { Package } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [requests, setRequests] = useState<EquipmentRequest[]>([
    {
      id: 'REQ-1',
      requesterId: '2',
      employeeId: '1',
      items: ['Notebook', 'Mouse', 'Monitor'],
      status: 'Pendente',
      createdAt: '2024-03-20',
      observation: 'Colaborador novo iniciando na próxima segunda-feira. Necessita de setup completo.'
    }
  ]);

  const handleAddAsset = (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      id: `AST-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${Math.random().toString(36).substr(2, 9)}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleUpdateAsset = (updatedAsset: Asset) => {
    setAssets(assets.map(a => a.id === updatedAsset.id ? updatedAsset : a));
  };

  const handleAddEmployee = (empData: Omit<Employee, 'id'>) => {
    const newEmp: Employee = {
      ...empData,
      id: String(employees.length + 1)
    };
    setEmployees([newEmp, ...employees]);
  };

  const handleAddRequest = (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const newReq: EquipmentRequest = {
      ...reqData,
      id: `REQ-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      status: 'Pendente',
      createdAt: new Date().toLocaleDateString('pt-BR')
    };
    setRequests([newReq, ...requests]);
  };

  const handleUpdateStatus = (id: string, status: EquipmentRequest['status']) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status } : r));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} />;
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
