        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      case 'requests':
        return (
          <RequestsManager 
            requests={requests} 
            employees={employees} 
            onAddRequest={handleAddRequest} 
            onUpdateStatus={handleUpdateStatus}
          />
        );
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'inventory-check':
        return (
          <div className="flex flex-col items-center justify-center py-20 text-center space-y-4">
            <div className="w-20 h-20 bg-blue-100 rounded-full flex items-center justify-center text-blue-600">
              <Package className="w-10 h-10" />
            </div>
            <h3 className="text-2xl font-bold text-slate-800">Verificação Semestral de Inventário</h3>
            <p className="text-slate-500 max-w-md">
              A próxima auditoria geral de ativos está programada para <strong>Junho de 2024</strong>. 
              Nesta etapa, validaremos desgaste, mau uso e presença física dos itens.
            </p>
            <button className="bg-slate-800 text-white px-8 py-3 rounded-2xl font-bold">Iniciar Pré-Auditoria</button>
          </div>
        );
      default:
        return <Dashboard assets={assets} />;
    }
  };

  if (!isAuthenticated) {
    return <Auth onLogin={() => setIsAuthenticated(true)} />;
  }

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  FileText, 
  Send, 
  CheckCircle, 
  Clock, 
  ChevronRight, 
  MessageSquare, 
  Plus, 
  X, 
  User, 
  Calendar, 
  AlertCircle,
  Check,
  Ban,
  Truck
} from 'lucide-react';
