  const toggleItem = (type: AssetType) => {
    setNewReq(prev => ({
      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddRequest(newReq);
    setShowModal(false);
    setNewReq({ requesterId: '2', employeeId: '', items: [], observation: '' });
  };

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'Desconhecido';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Geral';

  const handleStatusChange = (status: EquipmentRequest['status']) => {
    if (selectedRequest) {
      onUpdateStatus(selectedRequest.id, status);
      setSelectedRequest({ ...selectedRequest, status });
    }
  };

  const handleLinkAsset = (index: number, assetId: string) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      ...newFulfillments[index],
      linkedAssetId: assetId,
      isPurchaseOrder: false
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleRequestPurchase = (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      ...newFulfillments[index],
      linkedAssetId: undefined,
      isPurchaseOrder: true,
      purchaseStatus: 'Pendente'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    onUpdateRequest(updated);
    setSelectedRequest(updated);
    setItemToLink(null);
  };

  const handleApprovePurchase = (index: number) => {
    if (!selectedRequest) return;
    const newFulfillments = [...(selectedRequest.itemFulfillments || [])];
    newFulfillments[index] = {
      ...newFulfillments[index],
      purchaseStatus: 'Aprovado'
    };
    const updated = { ...selectedRequest, itemFulfillments: newFulfillments };
    onUpdateRequest(updated);
    setSelectedRequest(updated);
  };

  const availableAssetsByType = (type: AssetType) => {
    return assets.filter(a => a.type === type && a.status === 'Disponível');
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 relative">
      <div className="lg:col-span-2 space-y-4">
        <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
          <Clock className="w-5 h-5 text-blue-600" /> Requisições Ativas
        </h3>
        {requests.map(req => (
          <div 
            key={req.id} 
            onClick={() => setSelectedRequest(req)}
            className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between hover:shadow-md transition-all group cursor-pointer"
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${
                req.status === 'Pendente' ? 'bg-amber-50 text-amber-500' :
                req.status === 'Aprovado' ? 'bg-blue-50 text-blue-500' :
                req.status === 'Entregue' ? 'bg-emerald-50 text-emerald-500' : 'bg-slate-50 text-slate-400'
              }`}>
                <FileText className="w-6 h-6" />
              </div>
              <div>
                <p className="font-bold text-slate-800">{req.id.startsWith('REQ') ? req.id : `REQ-${req.id.slice(0, 5)}`}</p>
                <p className="text-sm text-slate-500">Destino: {getEmployeeName(req.employeeId)}</p>
              </div>
            </div>
            <div className="flex items-center gap-6">
               <div className="hidden md:flex items-center gap-2">
                  {req.itemFulfillments?.some(f => f.isPurchaseOrder) && (
                    <span className="bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[10px] font-bold flex items-center gap-1">
                      <ShoppingCart className="w-3 h-3" /> Pedido Compra
                    </span>
                  )}
               </div>
               <span className={`px-4 py-1.5 rounded-full text-xs font-bold ${
                 req.status === 'Pendente' ? 'bg-amber-100 text-amber-600' : 
                 req.status === 'Aprovado' ? 'bg-blue-100 text-blue-600' :
                 req.status === 'Entregue' ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'
               }`}>
                 {req.status}
               </span>
               <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-blue-500 transition-transform group-hover:translate-x-1" />
            </div>
          </div>
        ))}
      </div>

      <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-lg h-fit space-y-6 sticky top-24">
        <h3 className="text-xl font-bold text-slate-800">Nova Requisição</h3>
        <p className="text-sm text-slate-500 leading-relaxed">
          O sistema vincula ativos em estoque ou gera pedidos de compra caso não haja disponibilidade.
        </p>
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-blue-200 flex items-center justify-center gap-2 transition-all transform active:scale-[0.98]"
        >
          <Plus className="w-5 h-5" />
          <span>Solicitar Equipamento</span>
        </button>
      </div>

      {/* Request Details Slide-over Panel */}
      {selectedRequest && (
        <div className="fixed inset-0 z-[70] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => { setSelectedRequest(null); setItemToLink(null); }} />
          <div className="relative w-full max-w-xl bg-white h-full shadow-2xl flex flex-col animate-slide-in-right">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-slate-50">
              <div>
                <h3 className="text-xl font-bold text-slate-800">Gerenciamento de Requisição</h3>
                <p className="text-sm text-slate-500">{selectedRequest.id}</p>
              </div>
              <button onClick={() => { setSelectedRequest(null); setItemToLink(null); }} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-400" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              {/* Items Table / Fulfillment */}
              <div className="space-y-4">
                <h4 className="text-sm font-bold text-slate-700 flex items-center gap-2">
                  <CheckSquare className="w-4 h-4 text-blue-600" /> Checklist de Atendimento
                </h4>
                <div className="space-y-3">
                  {selectedRequest.itemFulfillments?.map((fulfillment, idx) => (
                    <div key={idx} className="border border-slate-100 rounded-2xl p-4 bg-white shadow-sm space-y-3">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className={`p-2 rounded-xl ${fulfillment.linkedAssetId ? 'bg-blue-50 text-blue-600' : fulfillment.isPurchaseOrder ? 'bg-amber-50 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <FileText className="w-5 h-5" />
                          </div>
                          <span className="font-bold text-slate-800">{fulfillment.type}</span>
                        </div>
                        {fulfillment.linkedAssetId ? (
                          <span className="text-[10px] font-black uppercase text-blue-600 flex items-center gap-1">
                            <LinkIcon className="w-3 h-3" /> Vinculado: {fulfillment.linkedAssetId}
                          </span>
                        ) : fulfillment.isPurchaseOrder ? (
                          <span className={`text-[10px] font-black uppercase flex items-center gap-1 ${fulfillment.purchaseStatus === 'Aprovado' ? 'text-emerald-600' : 'text-amber-600'}`}>
                            <ShoppingCart className="w-3 h-3" /> Pedido {fulfillment.purchaseStatus}
                          </span>
                        ) : (
                          <span className="text-[10px] font-black uppercase text-slate-400">Aguardando</span>
                        )}
                      </div>

                      {/* Fulfillment Actions */}
                      {!fulfillment.linkedAssetId && !fulfillment.isPurchaseOrder && (
                        <div className="flex gap-2 pt-2">
                          <button 
                            onClick={() => setItemToLink({ index: idx, type: fulfillment.type })}
                            className="flex-1 py-2 text-xs font-bold bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-100 transition-colors flex items-center justify-center gap-1"
                          >
                            <LinkIcon className="w-3 h-3" /> Vincular Ativo
                          </button>
                          <button 
                            onClick={() => handleRequestPurchase(idx)}
                            className="flex-1 py-2 text-xs font-bold bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-100 transition-colors flex items-center justify-center gap-1"
                          >
                            <ShoppingCart className="w-3 h-3" /> Solicitar Compra
                          </button>
                        </div>
                      )}

                      {/* Approval Action for Purchase Order */}
                      {fulfillment.isPurchaseOrder && fulfillment.purchaseStatus === 'Pendente' && (
                        <div className="bg-amber-50 p-3 rounded-xl flex items-center justify-between">
                          <p className="text-[10px] text-amber-700 font-medium">Este item requer aprovação de compra por não haver saldo em estoque.</p>
                          <button 
                            onClick={() => handleApprovePurchase(idx)}
                            className="bg-amber-600 text-white px-3 py-1.5 rounded-lg text-[10px] font-bold hover:bg-amber-700 transition-colors"
                          >
                            Aprovar Compra
                          </button>
                        </div>
                      )}

                      {/* Link Asset Sub-panel */}
                      {itemToLink?.index === idx && (
                        <div className="mt-4 p-4 bg-slate-50 rounded-xl border border-slate-200 animate-in fade-in slide-in-from-top-2">
                           <div className="flex items-center justify-between mb-3">
                              <h5 className="text-xs font-bold text-slate-600">Ativos Disponíveis:</h5>
                              <button onClick={() => setItemToLink(null)}><X className="w-3 h-3 text-slate-400" /></button>
                           </div>
                           <div className="space-y-2 max-h-40 overflow-y-auto pr-1">
                              {availableAssetsByType(fulfillment.type).length > 0 ? (
                                availableAssetsByType(fulfillment.type).map(asset => (
                                  <button 
                                    key={asset.id}
                                    onClick={() => handleLinkAsset(idx, asset.id)}
                                    className="w-full text-left p-2 rounded-lg bg-white border border-slate-100 hover:border-blue-300 hover:shadow-sm transition-all flex items-center justify-between"
                                  >
                                     <div className="flex flex-col">
                                       <span className="text-xs font-bold text-slate-800">{asset.id}</span>
                                       <span className="text-[10px] text-slate-400">{asset.brand} - {asset.model}</span>
                                     </div>
                                     <ChevronRight className="w-3 h-3 text-slate-300" />
                                  </button>
                                ))
                              ) : (
                                <div className="text-center py-4 text-[10px] text-slate-400 font-medium">
                                  Nenhum ativo "{fulfillment.type}" disponível em estoque.
                                </div>
                              )}
                           </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              {/* General Actions */}
              <div className="pt-4 border-t border-slate-100">
                <h4 className="text-sm font-bold text-slate-700 mb-4">Ações da Requisição</h4>
                <div className="grid grid-cols-2 gap-3">
                   <button 
                    onClick={() => handleStatusChange('Aprovado')}
                    className={`p-4 rounded-2xl flex flex-col items-center gap-2 transition-all border ${
                      selectedRequest.status === 'Aprovado' ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                   >
                     <Check className="w-5 h-5" />
                     <span className="text-xs font-bold">Aprovar Geral</span>
                   </button>
                   <button 
                    onClick={() => handleStatusChange('Entregue')}
                    disabled={selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder)}
                    className={`p-4 rounded-2xl flex flex-col items-center gap-2 transition-all border ${
                      selectedRequest.status === 'Entregue' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 
                      selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder) ? 'bg-slate-100 text-slate-300 cursor-not-allowed border-transparent' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                    }`}
                   >
                     <Truck className="w-5 h-5" />
                     <span className="text-xs font-bold">Marcar Entregue</span>
                   </button>
                </div>
                {selectedRequest.itemFulfillments?.some(f => !f.linkedAssetId && !f.isPurchaseOrder) && (
                  <p className="mt-3 text-[10px] text-rose-500 font-bold text-center">Vincule todos os itens ou solicite compras para habilitar entrega.</p>
                )}
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex gap-3">
               <button 
                onClick={() => setSelectedRequest(null)}
                className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg"
               >
                 Salvar e Sair
               </button>
            </div>
          </div>
        </div>
      )}

      {/* Form Modal (Nova Requisição) */}
      {showModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
             <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="text-xl font-bold text-slate-800">Nova Requisição de Ativos</h3>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-500" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-6">
              <div>
                <label className="text-sm font-bold text-slate-700 block mb-2">Colaborador Destinatário</label>
                <select 
                  className="w-full p-4 rounded-2xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500"
                  value={newReq.employeeId}
                  onChange={e => setNewReq({...newReq, employeeId: e.target.value})}
                  required
                >
                  <option value="">Escolher colaborador...</option>
                  {employees.map(e => <option key={e.id} value={e.id}>{e.name} ({e.sector})</option>)}
                </select>
              </div>

              <div>
                <label className="text-sm font-bold text-slate-700 block mb-4">Itens Necessários</label>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                  {ASSET_TYPES.map(type => (
                    <button
                      key={type}
                      type="button"
                      onClick={() => toggleItem(type as AssetType)}
                      className={`p-3 rounded-2xl border text-sm font-medium transition-all text-center ${
                        newReq.items.includes(type as AssetType)
                          ? 'bg-blue-600 border-blue-600 text-white shadow-md'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-blue-300'
                      }`}
                    >
                      {type}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="text-sm font-bold text-slate-700 block mb-2 flex items-center gap-2">
                  <MessageSquare className="w-4 h-4" /> Justificativa ou Observações
                </label>
                <textarea 
                  rows={4}
                  className="w-full p-4 rounded-2xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                  placeholder="Ex: Novos funcionários, troca por defeito, etc."
                  value={newReq.observation}
                  onChange={e => setNewReq({...newReq, observation: e.target.value})}
                />
              </div>

              <div className="flex justify-end gap-3 pt-4 border-t border-slate-100">
                <button type="button" onClick={() => setShowModal(false)} className="px-6 py-3 font-bold text-slate-500">Cancelar</button>
                <button type="submit" className="px-10 py-3 font-bold bg-blue-600 text-white rounded-2xl shadow-lg shadow-blue-200">Prosseguir para Triagem</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes slide-in-right {
          from { transform: translateX(100%); }
          to { transform: translateX(0); }
        }
        .animate-slide-in-right {
          animation: slide-in-right 0.3s ease-out;
        }
      `}</style>
    </div>
  );
};

