              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Destinado a</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Origem/Req</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status Financeiro</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredItems.map((item, idx) => (
              <tr key={`${item.request.id}-${idx}`} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
