                    <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-medium text-slate-700">{getEmployeeName(item.request.employeeId)}</span>
                    <span className="text-xs text-slate-400 italic">Novo Ativo</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2 text-xs font-mono bg-slate-100 px-2 py-1 rounded w-fit">
                    <FileText className="w-3 h-3" />
                    {item.request.id}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider ${
                    item.fulfillment.purchaseStatus === 'Pendente' ? 'bg-amber-100 text-amber-600' :
                    item.fulfillment.purchaseStatus === 'Aprovado' ? 'bg-emerald-100 text-emerald-600' :
                    'bg-blue-100 text-blue-600'
                  }`}>
                    {item.fulfillment.purchaseStatus}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  {item.fulfillment.purchaseStatus === 'Pendente' ? (
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => handleReject(item.request, item.index)}
                        className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"
                        title="Negar Compra"
                      >
                        <Ban className="w-5 h-5" />
                      </button>
                      <button 
                        onClick={() => handleApprove(item.request, item.index)}
                        className="p-2 text-emerald-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all"
                        title="Aprovar Compra"
                      >
                        <Check className="w-5 h-5" />
                      </button>
                    </div>
                  ) : (
                    <div className="flex justify-end text-slate-300">
                       <CheckCircle className="w-5 h-5" />
                    </div>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>

        {filteredItems.length === 0 && (
          <div className="p-16 text-center">
             <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                <ShoppingCart className="w-8 h-8 text-slate-200" />
             </div>
             <p className="text-slate-400 font-medium">Nenhum pedido de compra pendente para os filtros selecionados.</p>
          </div>
        )}
      </div>

      <div className="bg-blue-50 border border-blue-100 p-6 rounded-3xl flex items-start gap-4">
         <AlertCircle className="w-6 h-6 text-blue-500 shrink-0" />
         <div>
            <h4 className="font-bold text-blue-900 text-sm mb-1">Nota da IA (Financeiro)</h4>
            <p className="text-xs text-blue-700 leading-relaxed">
              Baseado no histórico de requisições, detectamos um aumento de 15% na demanda por Notebooks este mês. 
              A aprovação antecipada destes pedidos pode garantir melhores negociações com fornecedores habituais.
            </p>
         </div>
      </div>
    </div>
  );
};

