      ...prev,
      items: prev.items.includes(type) ? prev.items.filter(i => i !== type) : [...prev.items, type]
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddRequest(newReq);
    setShowModal(false);
    setNewReq({ requesterId: '2', employeeId: '', items: [], observation: '' });
