import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  CheckCircle, 
  Clock, 
  DollarSign, 
  Search, 
  Check, 
  Ban, 
  Filter, 
  AlertCircle,
  CreditCard,
  ArrowUpRight,
  TrendingUp,
  FileText,
  User,
  Package
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment } from '../types';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => void;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ requests, employees, onUpdateRequest }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Pendente');

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      employee?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'Todos' || item.fulfillment.purchaseStatus === statusFilter;

    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'N/A';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Geral';

  const handleApprove = (req: EquipmentRequest, index: number) => {
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[index] = {
      ...newFulfillments[index],
      purchaseStatus: 'Aprovado'
    };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleReject = (req: EquipmentRequest, index: number) => {
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[index] = {
      ...newFulfillments[index],
      isPurchaseOrder: false,
      purchaseStatus: undefined
    };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const totalPending = purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pendente').length;
  const estimatedCost = totalPending * 3800; // Mock cost estimation

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Financial Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm relative overflow-hidden group">
           <div className="relative z-10 flex items-center gap-5">
             <div className="w-14 h-14 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform">
               <Clock className="w-7 h-7" />
             </div>
             <div>
               <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Aguardando Avaliação</p>
               <p className="text-3xl font-black text-slate-800 tracking-tight">{totalPending}</p>
             </div>
           </div>
           <div className="absolute top-0 right-0 p-2 opacity-10">
              <TrendingUp className="w-16 h-16 text-slate-900" />
           </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center">
             <CheckCircle className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Aprovados (30 dias)</p>
             <p className="text-3xl font-black text-slate-800 tracking-tight">
               {purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Aprovado').length + 8}
             </p>
           </div>
        </div>

        <div className="bg-slate-900 p-6 rounded-[2rem] text-white shadow-2xl shadow-slate-200 flex items-center gap-5 relative overflow-hidden">
           <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center text-emerald-400">
             <CreditCard className="w-7 h-7" />
           </div>
           <div className="relative z-10">
             <p className="text-xs font-black text-slate-500 uppercase tracking-widest">Budget Estimado Solicitado</p>
             <p className="text-3xl font-black tracking-tight">R$ {estimatedCost.toLocaleString('pt-BR')},00</p>
           </div>
           <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-emerald-500/10 rounded-full blur-3xl"></div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Filtrar por equipamento ou beneficiário..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm">
          {['Todos', 'Pendente', 'Aprovado', 'Comprado'].map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                statusFilter === status 
                  ? 'bg-slate-900 text-white shadow-lg' 
                  : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Item / Categoria</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Beneficiário</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Origem</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Fin.</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item, idx) => (
                <tr key={`${item.request.id}-${idx}`} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <Package className="w-5 h-5" />
                      </div>
                      <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-blue-50 text-blue-500 flex items-center justify-center">
                        <User className="w-4 h-4" />
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{getEmployeeName(item.request.employeeId)}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase">{getEmployeeSector(item.request.employeeId)}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="inline-flex items-center gap-2 text-[11px] font-mono font-bold bg-slate-100 px-2 py-1 rounded-lg text-slate-600">
                      <FileText className="w-3 h-3" />
                      {item.request.id}
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                      item.fulfillment.purchaseStatus === 'Pendente' ? 'bg-amber-100 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Aprovado' ? 'bg-emerald-100 text-emerald-600 border-emerald-200' :
                      'bg-blue-100 text-blue-600 border-blue-200'
                    }`}>
                      {item.fulfillment.purchaseStatus}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    {item.fulfillment.purchaseStatus === 'Pendente' ? (
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => handleReject(item.request, item.index)}
                          className="w-10 h-10 flex items-center justify-center text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                          title="Negar/Remover"
                        >
                          <Ban className="w-5 h-5" />
                        </button>
                        <button 
                          onClick={() => handleApprove(item.request, item.index)}
                          className="w-10 h-10 flex items-center justify-center bg-slate-900 text-white hover:bg-black rounded-xl transition-all shadow-lg shadow-slate-200"
                          title="Aprovar Compra"
                        >
                          <Check className="w-5 h-5" />
                        </button>
                      </div>
                    ) : (
                      <div className="flex justify-end text-emerald-500">
                         <div className="bg-emerald-50 px-3 py-1 rounded-lg flex items-center gap-2">
                           <CheckCircle className="w-4 h-4" />
                           <span className="text-[10px] font-bold">Aprovado</span>
                         </div>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {filteredItems.length === 0 && (
            <div className="p-20 text-center flex flex-col items-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                  <ShoppingCart className="w-10 h-10 text-slate-200" />
               </div>
               <p className="text-slate-400 font-bold">Tudo em ordem! Nenhum pedido de compra pendente.</p>
               <p className="text-sm text-slate-300">As requisições que não possuem estoque aparecerão aqui para aprovação.</p>
            </div>
          )}
        </div>
      </div>

      <div className="bg-gradient-to-r from-blue-600 to-indigo-700 p-8 rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl shadow-blue-200">
         <div className="flex items-start gap-5">
            <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center">
               <TrendingUp className="w-8 h-8" />
            </div>
            <div>
               <h4 className="text-xl font-black tracking-tight">Análise Preditiva de Suprimentos</h4>
               <p className="text-blue-100 text-sm max-w-xl leading-relaxed">
                  O sistema identificou um aumento de solicitações de <strong>Notebooks</strong> por novos colaboradores.
                  Considere fechar um contrato anual com fornecedores para reduzir o custo unitário em até 12%.
               </p>
            </div>
         </div>
         <button className="bg-white text-blue-600 px-8 py-4 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-blue-50 transition-all shadow-xl">
            Ver Relatório Completo
         </button>
      </div>
    </div>
  );
};

