  const [isPrinting, setIsPrinting] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Pendente Documentos',
    photos: []
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd(newAsset as Omit<Asset, 'id' | 'createdAt' | 'qrCode'>);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Pendente Documentos', photos: [] });
  };

  const handleUpdateDetail = (updates: Partial<Asset>) => {
    if (!selectedAsset) return;
    const updated = { ...selectedAsset, ...updates };
    setSelectedAsset(updated);
    onUpdate(updated);
  };

  const handleAddPhoto = () => {
    // Simulating photo addition
    const newPhotoUrl = `https://picsum.photos/400/300?random=${Math.random()}`;
    if (selectedAsset) {
      handleUpdateDetail({ photos: [...selectedAsset.photos, newPhotoUrl] });
    }
  };

  const handleRemovePhoto = (index: number) => {
    if (selectedAsset) {
      const newPhotos = selectedAsset.photos.filter((_, i) => i !== index);
      handleUpdateDetail({ photos: newPhotos });
    }
  };

  const handlePrintLabel = () => {
    setIsPrinting(true);
    setTimeout(() => {
      window.print();
      setIsPrinting(false);
    }, 500);
  };

  const filteredAssets = assets.filter(a => {
    const matchesSearch = a.model.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          a.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          a.brand.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = filterType === 'all' || a.type === filterType;

    let matchesAvailability = true;
    if (filterAvailability === 'available') {
      matchesAvailability = !a.assignedTo;
    } else if (filterAvailability === 'assigned') {
      matchesAvailability = !!a.assignedTo;
    }

    return matchesSearch && matchesType && matchesAvailability;
  });

  const getAssignedEmployee = (id?: string) => employees.find(e => e.id === id);

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
