              </div>

              <div className="space-y-3">
                 <h5 className="text-sm font-bold text-slate-700">Observações Gerais</h5>
                 <textarea 
                   className="w-full text-sm text-slate-600 leading-relaxed italic bg-white p-4 rounded-2xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500 shadow-sm resize-none"
                   rows={3}
                   value={selectedAsset.observations || ''}
                   onChange={(e) => handleUpdateDetail({ observations: e.target.value })}
                   placeholder="Adicione observações técnicas..."
                 />
              </div>
            </div>

            <div className="p-6 border-t border-slate-100 bg-slate-50 flex gap-3">
