import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  CheckCircle, 
  Clock, 
  Search, 
  Check, 
  Ban, 
  AlertCircle,
  CreditCard,
  TrendingUp,
  FileText,
  User,
  Package,
  ExternalLink,
  Plus,
  Calendar,
  Truck,
  X,
  Link as LinkIcon
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation } from '../types';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => void;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ requests, employees, onUpdateRequest }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Pendente');
  const [selectedItem, setSelectedItem] = useState<{ request: EquipmentRequest; index: number } | null>(null);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        // Mostra apenas itens de compra que não foram marcados como entregues
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      employee?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'Todos' || item.fulfillment.purchaseStatus === statusFilter;

    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'N/A';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Geral';

  const handleUpdateQuotation = (qIndex: number, field: keyof Quotation, value: string) => {
    if (!selectedItem) return;
    const req = selectedItem.request;
    const fIdx = selectedItem.index;
    const newFulfillments = [...(req.itemFulfillments || [])];
    const quotations = [...(newFulfillments[fIdx].quotations || [{url:'', deliveryPrediction:''}, {url:'', deliveryPrediction:''}, {url:'', deliveryPrediction:''}])];

    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    newFulfillments[fIdx] = { ...newFulfillments[fIdx], quotations };

    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = (qIndex: number) => {
    if (!selectedItem) return;
    const req = selectedItem.request;
    const fIdx = selectedItem.index;
    const newFulfillments = [...(req.itemFulfillments || [])];

    newFulfillments[fIdx] = { 
      ...newFulfillments[fIdx], 
      purchaseStatus: 'Aprovado',
      approvedQuotationIndex: qIndex
    };

    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = () => {
    if (!selectedItem) return;
    const req = selectedItem.request;
    const fIdx = selectedItem.index;
    const newFulfillments = [...(req.itemFulfillments || [])];

    newFulfillments[fIdx] = { 
      ...newFulfillments[fIdx], 
      purchaseStatus: 'Comprado'
    };

    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleSetDeliveryForecast = (date: string) => {
    if (!selectedItem) return;
    const req = selectedItem.request;
    const fIdx = selectedItem.index;
    const newFulfillments = [...(req.itemFulfillments || [])];

    newFulfillments[fIdx] = { 
      ...newFulfillments[fIdx], 
      deliveryForecastDate: date
    };

    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleFinalizeDelivery = (req: EquipmentRequest, fIdx: number) => {
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIdx] = { 
      ...newFulfillments[fIdx], 
      isDelivered: true 
    };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
    setSelectedItem(null);
  };

  const totalPending = purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pendente').length;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Financial Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center">
             <Clock className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Aguardando Cotação</p>
             <p className="text-3xl font-black text-slate-800 tracking-tight">{totalPending}</p>
           </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
             <ShoppingCart className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Em Trânsito / Comprados</p>
             <p className="text-3xl font-black text-slate-800 tracking-tight">
               {purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length}
             </p>
           </div>
        </div>

        <div className="bg-slate-900 p-6 rounded-[2rem] text-white shadow-2xl shadow-slate-200 flex items-center gap-5">
           <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center text-emerald-400">
             <Truck className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-500 uppercase tracking-widest">Entrega Finalizada</p>
             <p className="text-3xl font-black tracking-tight">Sucesso</p>
           </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Filtrar por equipamento ou beneficiário..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm bg-white"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm">
          {['Todos', 'Pendente', 'Aprovado', 'Comprado'].map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                statusFilter === status 
                  ? 'bg-slate-900 text-white shadow-lg' 
                  : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Item / Categoria</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Beneficiário</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Previsão Entrega</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Compra</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item, idx) => (
                <tr 
                  key={`${item.request.id}-${idx}`} 
                  onClick={() => setSelectedItem({ request: item.request, index: item.index })}
                  className="hover:bg-slate-50/50 transition-colors group cursor-pointer"
                >
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <Package className="w-5 h-5" />
                      </div>
                      <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div>
                      <p className="text-sm font-bold text-slate-800">{getEmployeeName(item.request.employeeId)}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase">{getEmployeeSector(item.request.employeeId)}</p>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    {item.fulfillment.deliveryForecastDate ? (
                      <div className="flex items-center gap-2 text-blue-600 font-bold text-xs">
                        <Calendar className="w-4 h-4" />
                        {item.fulfillment.deliveryForecastDate}
                      </div>
                    ) : (
                      <span className="text-xs text-slate-300 italic">Não definida</span>
                    )}
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                      item.fulfillment.purchaseStatus === 'Pendente' ? 'bg-amber-100 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Aprovado' ? 'bg-emerald-100 text-emerald-600 border-emerald-200' :
                      'bg-blue-600 text-white border-blue-700 shadow-md'
                    }`}>
                      {item.fulfillment.purchaseStatus}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      {item.fulfillment.purchaseStatus === 'Comprado' && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleFinalizeDelivery(item.request, item.index); }}
                          className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-xs shadow-lg hover:bg-emerald-700"
                        >
                          Finalizar Entrega
                        </button>
                      )}
                      <button className="p-2 text-slate-400 hover:text-blue-600">
                        <Plus className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {filteredItems.length === 0 && (
            <div className="p-20 text-center flex flex-col items-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                  <ShoppingCart className="w-10 h-10 text-slate-200" />
               </div>
               <p className="text-slate-400 font-bold">Nenhum pedido ativo no dashboard de compras.</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal de Detalhes da Compra / Cotações */}
      {selectedItem && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setSelectedItem(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
             <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white">
                    <ShoppingCart className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-bold text-slate-800">Processo de Aquisição</h3>
                    <p className="text-sm text-slate-500">{selectedItem.request.id} • {selectedItem.request.itemFulfillments?.[selectedItem.index].type}</p>
                  </div>
                </div>
                <button onClick={() => setSelectedItem(null)} className="p-2 hover:bg-slate-100 rounded-full">
                  <X className="w-6 h-6 text-slate-400" />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-8 space-y-8">
                {/* 1. Cotações */}
                <div className="space-y-4">
                   <div className="flex items-center justify-between">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <FileText className="w-4 h-4 text-blue-600" /> Cotação Tripla Obrigatória
                      </h4>
                      <span className="text-[10px] text-amber-600 font-bold bg-amber-50 px-2 py-1 rounded-lg border border-amber-100">
                        Requisito Financeiro
                      </span>
                   </div>

                   <div className="grid grid-cols-1 gap-4">
                      {[0, 1, 2].map(qIdx => {
                        const q = selectedItem.request.itemFulfillments?.[selectedItem.index].quotations?.[qIdx] || { url: '', deliveryPrediction: '' };
                        const isApproved = selectedItem.request.itemFulfillments?.[selectedItem.index].approvedQuotationIndex === qIdx;
                        const status = selectedItem.request.itemFulfillments?.[selectedItem.index].purchaseStatus;

                        return (
                          <div key={qIdx} className={`p-6 rounded-[2rem] border transition-all ${
                            isApproved ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-100'
                          }`}>
                            <div className="flex items-center justify-between mb-4">
                               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cotação 0{qIdx + 1}</span>
                               {isApproved && (
                                 <span className="bg-emerald-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase">Aprovada</span>
                               )}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-500 uppercase">Link do Produto</label>
                                  <div className="relative">
                                    <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
                                    <input 
                                      className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-slate-200 text-xs focus:ring-2 focus:ring-blue-500 outline-none"
                                      placeholder="https://..."
                                      value={q.url}
                                      onChange={(e) => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                                      disabled={status === 'Comprado'}
                                    />
                                  </div>
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-500 uppercase">Prazo de Entrega</label>
                                  <input 
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 text-xs focus:ring-2 focus:ring-blue-500 outline-none"
                                    placeholder="Ex: 5 dias úteis"
                                    value={q.deliveryPrediction}
                                    onChange={(e) => handleUpdateQuotation(qIdx, 'deliveryPrediction', e.target.value)}
                                    disabled={status === 'Comprado'}
                                  />
                               </div>
                            </div>

                            {q.url && q.deliveryPrediction && status !== 'Comprado' && !isApproved && (
                              <button 
                                onClick={() => handleApproveQuotation(qIdx)}
                                className="mt-4 w-full bg-white border border-slate-200 py-2.5 rounded-xl text-xs font-bold text-slate-700 hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                              >
                                Aprovar esta cotação
                              </button>
                            )}
                          </div>
                        );
                      })}
                   </div>
                </div>

                {/* 2. Próximos Passos (Aprovado -> Comprado) */}
                {selectedItem.request.itemFulfillments?.[selectedItem.index].purchaseStatus === 'Aprovado' && (
                   <div className="bg-blue-600 p-8 rounded-[2.5rem] text-white space-y-4 shadow-xl shadow-blue-100">
                      <div className="flex items-center gap-3">
                         <CreditCard className="w-6 h-6" />
                         <h4 className="font-black uppercase tracking-widest text-sm">Liberação Financeira</h4>
                      </div>
                      <p className="text-sm text-blue-100 leading-relaxed">
                        A cotação foi aprovada. Prossiga com o pagamento e informe ao sistema quando o item for efetivamente comprado.
                      </p>
                      <button 
                        onClick={handleSetComprado}
                        className="w-full bg-white text-blue-600 font-bold py-4 rounded-2xl shadow-lg hover:bg-blue-50 transition-all"
                      >
                        Confirmar Pagamento / Compra Realizada
                      </button>
                   </div>
                )}

                {/* 3. Acompanhamento de Entrega */}
                {selectedItem.request.itemFulfillments?.[selectedItem.index].purchaseStatus === 'Comprado' && (
                  <div className="space-y-6">
                    <div className="p-8 bg-slate-900 rounded-[2.5rem] text-white space-y-6">
                        <div className="flex items-center gap-3">
                           <Truck className="w-6 h-6 text-emerald-400" />
                           <h4 className="font-black uppercase tracking-widest text-sm">Rastreamento de Entrega</h4>
                        </div>

                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Previsão de Entrega Final</label>
                           <input 
                            type="date"
                            className="w-full bg-white/10 border border-white/20 rounded-2xl p-4 text-white focus:ring-2 focus:ring-emerald-500 outline-none"
                            value={selectedItem.request.itemFulfillments?.[selectedItem.index].deliveryForecastDate || ''}
                            onChange={(e) => handleSetDeliveryForecast(e.target.value)}
                           />
                        </div>

                        <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-start gap-3">
                           <AlertCircle className="w-5 h-5 text-emerald-400 shrink-0" />
                           <p className="text-xs text-emerald-100 leading-relaxed">
                             Este item permanecerá no dashboard até que a entrega física seja confirmada pelo setor de TI.
                           </p>
                        </div>

                        <button 
                          onClick={() => handleFinalizeDelivery(selectedItem.request, selectedItem.index)}
                          className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-2xl shadow-xl transition-all"
                        >
                          Confirmar Recebimento e Finalizar
                        </button>
                    </div>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PurchaseOrderManager;

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  CheckCircle, 
  Clock, 
  Search, 
  Check, 
  Ban, 
  AlertCircle,
  CreditCard,
  TrendingUp,
  FileText,
  User,
  Package,
  ExternalLink,
  Plus,
  Calendar,
  Truck,
  X,
  Link as LinkIcon
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation } from '../types';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => void;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ requests, employees, onUpdateRequest }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Pendente');
  // Alterado para guardar apenas IDs para evitar stale state (estado travado)
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);

  // Busca o objeto real baseado nos IDs selecionados
  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      employee?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === 'Todos' || item.fulfillment.purchaseStatus === statusFilter;

    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'N/A';
  const getEmployeeSector = (id: string) => employees.find(e => e.id === id)?.sector || 'Geral';

  const handleUpdateQuotation = (qIndex: number, field: keyof Quotation, value: string) => {
    if (!currentRequest || activeSelection === null) return;

    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };

    const quotations = [...(item.quotations || [
      { url: '', deliveryPrediction: '' },
      { url: '', deliveryPrediction: '' },
      { url: '', deliveryPrediction: '' }
    ])];

    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;

    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;

    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Aprovado',
      approvedQuotationIndex: qIndex
    };

    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = () => {
    if (!currentRequest || activeSelection === null) return;

    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Comprado'
    };

    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetDeliveryForecast = (date: string) => {
    if (!currentRequest || activeSelection === null) return;

    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      deliveryForecastDate: date
    };

    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleFinalizeDelivery = (req: EquipmentRequest, fIdx: number) => {
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIdx] = { 
      ...newFulfillments[fIdx], 
      isDelivered: true 
    };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
    setActiveSelection(null);
  };

  const totalPending = purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pendente').length;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Financial Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-amber-100 text-amber-600 rounded-2xl flex items-center justify-center">
             <Clock className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Aguardando Cotação</p>
             <p className="text-3xl font-black text-slate-800 tracking-tight">{totalPending}</p>
           </div>
        </div>

        <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-5">
           <div className="w-14 h-14 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center">
             <ShoppingCart className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Em Trânsito / Comprados</p>
             <p className="text-3xl font-black text-slate-800 tracking-tight">
               {purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length}
             </p>
           </div>
        </div>

        <div className="bg-slate-900 p-6 rounded-[2rem] text-white shadow-2xl shadow-slate-200 flex items-center gap-5">
           <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center text-emerald-400">
             <Truck className="w-7 h-7" />
           </div>
           <div>
             <p className="text-xs font-black text-slate-500 uppercase tracking-widest">Atendimento Fluxo</p>
             <p className="text-3xl font-black tracking-tight">Gestão</p>
           </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Filtrar por equipamento ou beneficiário..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm bg-white"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm">
          {['Todos', 'Pendente', 'Aprovado', 'Comprado'].map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                statusFilter === status 
                  ? 'bg-slate-900 text-white shadow-lg' 
                  : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-100">
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Item / Categoria</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Beneficiário</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Previsão Entrega</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Compra</th>
                <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.map((item, listIdx) => (
                <tr 
                  key={`${item.request.id}-${item.index}`} 
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                  className="hover:bg-slate-50/50 transition-colors group cursor-pointer"
                >
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <Package className="w-5 h-5" />
                      </div>
                      <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div>
                      <p className="text-sm font-bold text-slate-800">{getEmployeeName(item.request.employeeId)}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase">{getEmployeeSector(item.request.employeeId)}</p>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    {item.fulfillment.deliveryForecastDate ? (
                      <div className="flex items-center gap-2 text-blue-600 font-bold text-xs">
                        <Calendar className="w-4 h-4" />
                        {item.fulfillment.deliveryForecastDate}
                      </div>
                    ) : (
                      <span className="text-xs text-slate-300 italic">Não definida</span>
                    )}
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                      item.fulfillment.purchaseStatus === 'Pendente' ? 'bg-amber-100 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Aprovado' ? 'bg-emerald-100 text-emerald-600 border-emerald-200' :
                      'bg-blue-600 text-white border-blue-700 shadow-md'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      {item.fulfillment.purchaseStatus === 'Comprado' && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleFinalizeDelivery(item.request, item.index); }}
                          className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-xs shadow-lg hover:bg-emerald-700"
                        >
                          Finalizar Entrega
                        </button>
                      )}
                      <button className="p-2 text-slate-400 hover:text-blue-600">
                        <Plus className="w-5 h-5" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {filteredItems.length === 0 && (
            <div className="p-20 text-center flex flex-col items-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                  <ShoppingCart className="w-10 h-10 text-slate-200" />
               </div>
               <p className="text-slate-400 font-bold">Nenhum pedido ativo no dashboard de compras.</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal de Detalhes da Compra / Cotações */}
      {activeSelection && currentRequest && currentFulfillment && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setActiveSelection(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
             <div className="p-6 border-b border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white">
                    <ShoppingCart className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="text-xl font-bold text-slate-800">Processo de Aquisição</h3>
                    <p className="text-sm text-slate-500">{currentRequest.id} • {currentFulfillment.type}</p>
                  </div>
                </div>
                <button onClick={() => setActiveSelection(null)} className="p-2 hover:bg-slate-100 rounded-full">
                  <X className="w-6 h-6 text-slate-400" />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-8 space-y-8">
                {/* 1. Cotações */}
                <div className="space-y-4">
                   <div className="flex items-center justify-between">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <FileText className="w-4 h-4 text-blue-600" /> Cotação Tripla Obrigatória
                      </h4>
                      <span className="text-[10px] text-amber-600 font-bold bg-amber-50 px-2 py-1 rounded-lg border border-amber-100">
                        Requisito Financeiro
                      </span>
                   </div>

                   <div className="grid grid-cols-1 gap-4">
                      {[0, 1, 2].map(qIdx => {
                        const q = currentFulfillment.quotations?.[qIdx] || { url: '', deliveryPrediction: '' };
                        const isApproved = currentFulfillment.approvedQuotationIndex === qIdx;
                        const status = currentFulfillment.purchaseStatus;

                        return (
                          <div key={qIdx} className={`p-6 rounded-[2rem] border transition-all ${
                            isApproved ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-100'
                          }`}>
                            <div className="flex items-center justify-between mb-4">
                               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cotação 0{qIdx + 1}</span>
                               {isApproved && (
                                 <span className="bg-emerald-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase">Aprovada</span>
                               )}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-500 uppercase">Link do Produto</label>
                                  <div className="relative">
                                    <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400" />
                                    <input 
                                      className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-slate-200 text-xs focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                                      placeholder="https://..."
                                      value={q.url}
                                      onChange={(e) => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                                      disabled={status === 'Comprado'}
                                    />
                                  </div>
                               </div>
                               <div className="space-y-1.5">
                                  <label className="text-[10px] font-black text-slate-500 uppercase">Prazo de Entrega</label>
                                  <input 
                                    className="w-full px-4 py-2.5 rounded-xl border border-slate-200 text-xs focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                                    placeholder="Ex: 5 dias úteis"
                                    value={q.deliveryPrediction}
                                    onChange={(e) => handleUpdateQuotation(qIdx, 'deliveryPrediction', e.target.value)}
                                    disabled={status === 'Comprado'}
                                  />
                               </div>
                            </div>

                            {q.url && q.deliveryPrediction && status !== 'Comprado' && !isApproved && (
                              <button 
                                onClick={() => handleApproveQuotation(qIdx)}
                                className="mt-4 w-full bg-white border border-slate-200 py-2.5 rounded-xl text-xs font-bold text-slate-700 hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                              >
                                Aprovar esta cotação
                              </button>
                            )}
                          </div>
                        );
                      })}
                   </div>
                </div>

                {/* 2. Próximos Passos (Aprovado -> Comprado) */}
                {currentFulfillment.purchaseStatus === 'Aprovado' && (
                   <div className="bg-blue-600 p-8 rounded-[2.5rem] text-white space-y-4 shadow-xl shadow-blue-100">
                      <div className="flex items-center gap-3">
                         <CreditCard className="w-6 h-6" />
                         <h4 className="font-black uppercase tracking-widest text-sm">Liberação Financeira</h4>
                      </div>
                      <p className="text-sm text-blue-100 leading-relaxed">
                        A cotação foi aprovada. Prossiga com o pagamento e informe ao sistema quando o item for efetivamente comprado.
                      </p>
                      <button 
                        onClick={handleSetComprado}
                        className="w-full bg-white text-blue-600 font-bold py-4 rounded-2xl shadow-lg hover:bg-blue-50 transition-all"
                      >
                        Confirmar Pagamento / Compra Realizada
                      </button>
                   </div>
                )}

                {/* 3. Acompanhamento de Entrega */}
                {currentFulfillment.purchaseStatus === 'Comprado' && (
                  <div className="space-y-6">
                    <div className="p-8 bg-slate-900 rounded-[2.5rem] text-white space-y-6">
                        <div className="flex items-center gap-3">
                           <Truck className="w-6 h-6 text-emerald-400" />
                           <h4 className="font-black uppercase tracking-widest text-sm">Rastreamento de Entrega</h4>
                        </div>

                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Previsão de Entrega Final</label>
                           <input 
                            type="date"
                            className="w-full bg-white/10 border border-white/20 rounded-2xl p-4 text-white focus:ring-2 focus:ring-emerald-500 outline-none"
                            value={currentFulfillment.deliveryForecastDate || ''}
                            onChange={(e) => handleSetDeliveryForecast(e.target.value)}
                           />
                        </div>

                        <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-start gap-3">
                           <AlertCircle className="w-5 h-5 text-emerald-400 shrink-0" />
                           <p className="text-xs text-emerald-100 leading-relaxed">
                             Este item permanecerá no dashboard até que a entrega física seja confirmada pelo setor de TI.
                           </p>
                        </div>

                        <button 
                          onClick={() => handleFinalizeDelivery(currentRequest, activeSelection.fIndex)}
                          className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-4 rounded-2xl shadow-xl transition-all"
                        >
                          Confirmar Recebimento e Finalizar
                        </button>
                    </div>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PurchaseOrderManager;

export type AssetType = 
  | 'Desktop' 
  | 'Notebook' 
  | 'Mouse' 
  | 'Cabo' 
  | 'Monitor' 
  | 'Teclado' 
  | 'Headset' 
  | 'Suporte Notebook';

export type AssetStatus = 'Disponível' | 'Em Uso' | 'Manutenção' | 'Baixado' | 'Pendente Documentos';

export interface Asset {
  id: string;
  type: AssetType;
  brand: string;
  model: string;
  ram?: string;
  storage?: string;
  processor?: string;
  screenSize?: string;
  observations: string;
  photos: string[];
  status: AssetStatus;
  assignedTo?: string; // Employee ID
  qrCode: string;
  createdAt: string;
}

export interface Employee {
  id: string;
  name: string;
  sector: string;
  role: string;
  cpf: string;
}

export type AppModule = 
  | 'dashboard' 
  | 'assets' 
  | 'employees' 
  | 'requests' 
  | 'purchase-orders' 
  | 'printing' 
  | 'user-management' 
  | 'inventory-check';

export interface UserAccount {
  id: string;
  name: string;
  username: string;
  password?: string;
  sector: string;
  modules: AppModule[];
}

export interface Quotation {
  url: string;
  price?: number;
  deliveryPrediction: string;
}

export interface ItemFulfillment {
  type: AssetType;
  linkedAssetId?: string;
  isPurchaseOrder: boolean;
  purchaseStatus?: 'Pendente' | 'Cotação Aprovada' | 'Pedido Autorizado' | 'Comprado';
  quotations?: Quotation[];
  approvedQuotationIndex?: number;
  deliveryForecastDate?: string;
  isDelivered?: boolean;
}

export interface EquipmentRequest {
  id: string;
  requesterId: string;
  employeeId: string;
  items: AssetType[];
  itemFulfillments?: ItemFulfillment[];
  observation?: string;
  status: 'Pendente' | 'Aprovado' | 'Preparando' | 'Entregue' | 'Cancelado';
  createdAt: string;
}

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  Clock, 
  Search, 
  Check, 
  AlertCircle,
  CreditCard,
  FileText,
  Package,
  Calendar,
  Truck,
  X,
  Link as LinkIcon,
  CheckSquare,
  Square,
  MoreHorizontal,
  ChevronRight,
  ShieldCheck,
  Zap
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation } from '../types';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => void;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ requests, employees, onUpdateRequest }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Todos');
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);
  const [bulkSelected, setBulkSelected] = useState<string[]>([]); // "requestId-fIndex"

  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      employee?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());

    const status = item.fulfillment.purchaseStatus || 'Pendente';
    const matchesStatus = statusFilter === 'Todos' || status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'N/A';

  const handleUpdateQuotation = (qIndex: number, field: keyof Quotation, value: string) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };
    const quotations = [...(item.quotations || [{ url: '', deliveryPrediction: '' }, { url: '', deliveryPrediction: '' }, { url: '', deliveryPrediction: '' }])];
    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Cotação Aprovada',
      approvedQuotationIndex: qIndex
    };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleAuthorizeOrder = () => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Pedido Autorizado'
    };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = (requestId: string, fIndex: number) => {
    const req = requests.find(r => r.id === requestId);
    if (!req) return;
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIndex] = { ...newFulfillments[fIndex], purchaseStatus: 'Comprado' };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleBulkMarkAsPurchased = () => {
    bulkSelected.forEach(id => {
      const [reqId, fIdx] = id.split('-');
      handleSetComprado(reqId, parseInt(fIdx));
    });
    setBulkSelected([]);
  };

  const handleFinalizeDelivery = (req: EquipmentRequest, fIdx: number) => {
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIdx] = { ...newFulfillments[fIdx], isDelivered: true };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
    setActiveSelection(null);
  };

  const handleSetDeliveryForecast = (date: string) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { ...newFulfillments[activeSelection.fIndex], deliveryForecastDate: date };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const toggleBulk = (id: string) => {
    setBulkSelected(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Stats Summary */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cotações Pendentes', count: purchaseItems.filter(i => (i.fulfillment.purchaseStatus || 'Pendente') === 'Pendente').length, color: 'amber' },
          { label: 'Aguard. Autorização', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Cotação Aprovada').length, color: 'blue' },
          { label: 'Pedidos Autorizados', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pedido Autorizado').length, color: 'indigo' },
          { label: 'Em Trânsito (Pagos)', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length, color: 'emerald' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
            <p className={`text-3xl font-black text-${stat.color}-600 tracking-tight`}>{stat.count}</p>
          </div>
        ))}
      </div>

      {/* Bulk Actions Bar */}
      {bulkSelected.length > 0 && (
        <div className="bg-slate-900 text-white p-6 rounded-[2rem] flex items-center justify-between shadow-2xl animate-in slide-in-from-top-4">
           <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center">
                 <ShoppingCart className="w-5 h-5 text-blue-400" />
              </div>
              <div>
                 <p className="font-bold">{bulkSelected.length} itens selecionados</p>
                 <p className="text-xs text-slate-400">Você pode processar a compra conjunta destes itens agora.</p>
              </div>
           </div>
           <div className="flex gap-3">
              <button onClick={() => setBulkSelected([])} className="px-6 py-2.5 rounded-xl font-bold text-slate-400 hover:text-white transition-colors">Cancelar</button>
              <button 
                onClick={handleBulkMarkAsPurchased}
                className="bg-blue-600 hover:bg-blue-700 px-8 py-2.5 rounded-xl font-bold shadow-lg flex items-center gap-2"
              >
                <CreditCard className="w-4 h-4" /> Confirmar Pagamento do Lote
              </button>
           </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por item ou colaborador..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm bg-white font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm overflow-x-auto max-w-full">
          {['Todos', 'Pendente', 'Cotação Aprovada', 'Pedido Autorizado', 'Comprado'].map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                statusFilter === status 
                  ? 'bg-slate-900 text-white shadow-lg' 
                  : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-5 w-12 text-center">
                 <div className="flex items-center justify-center">
                    <MoreHorizontal className="w-4 h-4 text-slate-300" />
                 </div>
              </th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipamento</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Atual</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredItems.map((item) => {
              const itemId = `${item.request.id}-${item.index}`;
              const isAutorizado = item.fulfillment.purchaseStatus === 'Pedido Autorizado';
              const isSelected = bulkSelected.includes(itemId);

              return (
                <tr 
                  key={itemId} 
                  className={`hover:bg-slate-50/50 transition-colors group cursor-pointer ${isSelected ? 'bg-blue-50/30' : ''}`}
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                >
                  <td className="px-6 py-6 text-center" onClick={(e) => e.stopPropagation()}>
                    {isAutorizado ? (
                      <button onClick={() => toggleBulk(itemId)}>
                        {isSelected ? <CheckSquare className="w-5 h-5 text-blue-600" /> : <Square className="w-5 h-5 text-slate-200" />}
                      </button>
                    ) : (
                      <div className="w-5 h-5" />
                    )}
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <Package className="w-5 h-5" />
                      </div>
                      <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    <p className="text-sm font-bold text-slate-700">{getEmployeeName(item.request.employeeId)}</p>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                      (item.fulfillment.purchaseStatus || 'Pendente') === 'Pendente' ? 'bg-amber-50 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Cotação Aprovada' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                      item.fulfillment.purchaseStatus === 'Pedido Autorizado' ? 'bg-indigo-50 text-indigo-600 border-indigo-200' :
                      'bg-emerald-600 text-white border-emerald-700'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <ChevronRight className="w-5 h-5 text-slate-300 ml-auto group-hover:translate-x-1 transition-transform" />
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Side Details Panel */}
      {activeSelection && currentRequest && currentFulfillment && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setActiveSelection(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
             <div className="p-8 border-b border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100">
                    <ShoppingCart className="w-7 h-7" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-800">Workflow de Compra</h3>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{currentRequest.id} • {currentFulfillment.type}</p>
                  </div>
                </div>
                <button onClick={() => setActiveSelection(null)} className="p-3 hover:bg-slate-100 rounded-full transition-colors">
                  <X className="w-6 h-6 text-slate-400" />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-8 space-y-10">
                {/* Status Progress Map */}
                <div className="flex items-center justify-between px-4">
                   {['Cotação', 'Aprovação', 'Autorização', 'Compra'].map((step, idx) => (
                     <div key={idx} className="flex flex-col items-center gap-2">
                        <div className={`w-3 h-3 rounded-full ${
                          (idx === 0) || 
                          (idx === 1 && currentFulfillment.purchaseStatus !== 'Pendente') ||
                          (idx === 2 && ['Pedido Autorizado', 'Comprado'].includes(currentFulfillment.purchaseStatus!)) ||
                          (idx === 3 && currentFulfillment.purchaseStatus === 'Comprado')
                            ? 'bg-blue-600' : 'bg-slate-200'
                        }`} />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{step}</span>
                     </div>
                   ))}
                </div>

                {/* Section 1: Cotações */}
                <div className="space-y-6">
                   <div className="flex items-center justify-between">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <FileText className="w-4 h-4 text-blue-600" /> Comparativo de Mercado
                      </h4>
                      {currentFulfillment.purchaseStatus === 'Pendente' && (
                        <span className="text-[10px] text-amber-600 bg-amber-50 px-3 py-1 rounded-lg border border-amber-200 font-bold uppercase">Preencher cotações</span>
                      )}
                   </div>

                   <div className="space-y-4">
                      {[0, 1, 2].map(qIdx => {
                        const q = currentFulfillment.quotations?.[qIdx] || { url: '', deliveryPrediction: '' };
                        const isChosen = currentFulfillment.approvedQuotationIndex === qIdx;
                        const canEdit = (currentFulfillment.purchaseStatus || 'Pendente') === 'Pendente';

                        return (
                          <div key={qIdx} className={`p-6 rounded-[2.5rem] border transition-all ${
                            isChosen ? 'bg-blue-50 border-blue-200' : 'bg-slate-50 border-slate-100'
                          }`}>
                            <div className="flex items-center justify-between mb-4">
                               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Opção de Fornecedor 0{qIdx + 1}</span>
                               {isChosen && <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase">Cotação Selecionada</span>}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div className="space-y-1">
                                  <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">URL / Link</label>
                                  <div className="relative">
                                    <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                                    <input 
                                      className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white font-medium"
                                      placeholder="Link do produto..."
                                      value={q.url}
                                      onChange={(e) => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                                      disabled={!canEdit}
                                    />
                                  </div>
                               </div>
                               <div className="space-y-1">
                                  <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Entrega Est.</label>
                                  <input 
                                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white font-medium"
                                    placeholder="Ex: 3 dias"
                                    value={q.deliveryPrediction}
                                    onChange={(e) => handleUpdateQuotation(qIdx, 'deliveryPrediction', e.target.value)}
                                    disabled={!canEdit}
                                  />
                               </div>
                            </div>

                            {canEdit && q.url && q.deliveryPrediction && (
                              <button 
                                onClick={() => handleApproveQuotation(qIdx)}
                                className="mt-4 w-full bg-white border border-slate-200 py-3 rounded-2xl text-xs font-black text-slate-700 hover:bg-slate-900 hover:text-white transition-all shadow-sm flex items-center justify-center gap-2 uppercase tracking-widest"
                              >
                                <Check className="w-4 h-4" /> Selecionar Fornecedor
                              </button>
                            )}
                          </div>
                        );
                      })}
                   </div>
                </div>

                {/* Section 2: Autorização */}
                {currentFulfillment.purchaseStatus === 'Cotação Aprovada' && (
                  <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white space-y-4 shadow-xl shadow-indigo-100 animate-in zoom-in-95">
                     <div className="flex items-center gap-3">
                        <ShieldCheck className="w-6 h-6" />
                        <h4 className="font-black uppercase tracking-widest text-sm">Autorização de Pedido</h4>
                     </div>
                     <p className="text-sm text-indigo-100 leading-relaxed">
                        A cotação foi selecionada com sucesso. Agora o gestor responsável deve autorizar o pedido para que o financeiro proceda com o pagamento.
                     </p>
                     <button 
                        onClick={handleAuthorizeOrder}
                        className="w-full bg-white text-indigo-600 font-black py-4 rounded-2xl shadow-lg hover:bg-indigo-50 transition-all uppercase tracking-widest flex items-center justify-center gap-2"
                     >
                        <Zap className="w-5 h-5" /> Autorizar Pedido Agora
                     </button>
                  </div>
                )}

                {/* Section 3: Pagamento (Status Pedido Autorizado) */}
                {currentFulfillment.purchaseStatus === 'Pedido Autorizado' && (
                  <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white space-y-4 shadow-2xl">
                     <div className="flex items-center gap-3">
                        <CreditCard className="w-6 h-6 text-blue-400" />
                        <h4 className="font-black uppercase tracking-widest text-sm">Liquidação de Pedido</h4>
                     </div>
                     <p className="text-sm text-slate-400 leading-relaxed">
                        Este pedido está autorizado. Você pode marcá-lo como pago individualmente aqui ou fechar um lote na tela principal.
                     </p>
                     <button 
                        onClick={() => handleSetComprado(currentRequest.id, activeSelection.fIndex)}
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest flex items-center justify-center gap-2"
                     >
                        Confirmar Pagamento Realizado
                     </button>
                  </div>
                )}

                {/* Section 4: Entrega (Status Comprado) */}
                {currentFulfillment.purchaseStatus === 'Comprado' && (
                  <div className="space-y-6 animate-in slide-in-from-bottom-4">
                     <div className="p-8 bg-emerald-600 rounded-[2.5rem] text-white space-y-6 shadow-xl">
                        <div className="flex items-center gap-3">
                           <Truck className="w-6 h-6" />
                           <h4 className="font-black uppercase tracking-widest text-sm">Acompanhamento Logístico</h4>
                        </div>

                        <div className="space-y-2">
                           <label className="text-[10px] font-black text-emerald-200 uppercase tracking-widest ml-1">Data Prevista de Chegada</label>
                           <input 
                            type="date"
                            className="w-full bg-emerald-700/50 border border-emerald-500 rounded-2xl p-4 text-white focus:ring-2 focus:ring-white outline-none font-bold"
                            value={currentFulfillment.deliveryForecastDate || ''}
                            onChange={(e) => handleSetDeliveryForecast(e.target.value)}
                           />
                        </div>

                        <div className="p-4 bg-white/10 rounded-2xl flex items-start gap-3">
                           <AlertCircle className="w-5 h-5 text-emerald-200 shrink-0" />
                           <p className="text-[10px] text-emerald-50 font-bold leading-relaxed uppercase">
                             O item permanecerá no dashboard até que o TI confirme o recebimento e o número de série.
                           </p>
                        </div>

                        <button 
                          onClick={() => handleFinalizeDelivery(currentRequest, activeSelection.fIndex)}
                          className="w-full bg-white text-emerald-600 font-black py-4 rounded-2xl shadow-xl hover:bg-emerald-50 transition-all uppercase tracking-widest"
                        >
                          Confirmar Entrega e Entrada no Estoque
                        </button>
                     </div>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PurchaseOrderManager;

import React, { useState, useMemo } from 'react';
import { 
  ShoppingCart, 
  Clock, 
  Search, 
  Check, 
  AlertCircle,
  CreditCard,
  FileText,
  Package,
  Calendar,
  Truck,
  X,
  Link as LinkIcon,
  CheckSquare,
  Square,
  MoreHorizontal,
  ChevronRight,
  ShieldCheck,
  Zap,
  Tag,
  QrCode
} from 'lucide-react';
import { EquipmentRequest, Employee, ItemFulfillment, Quotation, Asset, AssetType } from '../types';

interface PurchaseOrderManagerProps {
  requests: EquipmentRequest[];
  employees: Employee[];
  onUpdateRequest: (req: EquipmentRequest) => void;
  onAssetCreated: (asset: Omit<Asset, 'createdAt' | 'qrCode'>) => void;
}

const PurchaseOrderManager: React.FC<PurchaseOrderManagerProps> = ({ requests, employees, onUpdateRequest, onAssetCreated }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('Todos');
  const [activeSelection, setActiveSelection] = useState<{ requestId: string; fIndex: number } | null>(null);
  const [bulkSelected, setBulkSelected] = useState<string[]>([]); // "requestId-fIndex"
  const [showReceiptForm, setShowReceiptForm] = useState(false);

  // Dados para o cadastro no inventário
  const [receiptData, setReceiptData] = useState<Partial<Asset>>({
    brand: '',
    model: '',
    id: '',
    observations: ''
  });

  const currentRequest = useMemo(() => {
    if (!activeSelection) return null;
    return requests.find(r => r.id === activeSelection.requestId) || null;
  }, [requests, activeSelection]);

  const currentFulfillment = useMemo(() => {
    if (!currentRequest || activeSelection === null) return null;
    return currentRequest.itemFulfillments?.[activeSelection.fIndex] || null;
  }, [currentRequest, activeSelection]);

  const purchaseItems = useMemo(() => {
    const items: Array<{ request: EquipmentRequest; fulfillment: ItemFulfillment; index: number }> = [];
    requests.forEach(req => {
      req.itemFulfillments?.forEach((f, idx) => {
        if (f.isPurchaseOrder && !f.isDelivered) {
          items.push({ request: req, fulfillment: f, index: idx });
        }
      });
    });
    return items;
  }, [requests]);

  const filteredItems = purchaseItems.filter(item => {
    const employee = employees.find(e => e.id === item.request.employeeId);
    const matchesSearch = 
      item.fulfillment.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
      employee?.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.request.id.toLowerCase().includes(searchTerm.toLowerCase());

    const status = item.fulfillment.purchaseStatus || 'Pendente';
    const matchesStatus = statusFilter === 'Todos' || status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  const getEmployeeName = (id: string) => employees.find(e => e.id === id)?.name || 'N/A';

  const handleUpdateQuotation = (qIndex: number, field: keyof Quotation, value: string) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    const item = { ...newFulfillments[activeSelection.fIndex] };
    const quotations = [...(item.quotations || [{ url: '', deliveryPrediction: '' }, { url: '', deliveryPrediction: '' }, { url: '', deliveryPrediction: '' }])];
    quotations[qIndex] = { ...quotations[qIndex], [field]: value };
    item.quotations = quotations;
    newFulfillments[activeSelection.fIndex] = item;
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleApproveQuotation = (qIndex: number) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Cotação Aprovada',
      approvedQuotationIndex: qIndex
    };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleAuthorizeOrder = () => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      purchaseStatus: 'Pedido Autorizado'
    };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const handleSetComprado = (requestId: string, fIndex: number) => {
    const req = requests.find(r => r.id === requestId);
    if (!req) return;
    const newFulfillments = [...(req.itemFulfillments || [])];
    newFulfillments[fIndex] = { ...newFulfillments[fIndex], purchaseStatus: 'Comprado' };
    onUpdateRequest({ ...req, itemFulfillments: newFulfillments });
  };

  const handleBulkMarkAsPurchased = () => {
    bulkSelected.forEach(id => {
      const [reqId, fIdx] = id.split('-');
      handleSetComprado(reqId, parseInt(fIdx));
    });
    setBulkSelected([]);
  };

  const handleOpenReceipt = () => {
    if (!currentFulfillment) return;
    setReceiptData({
      brand: '',
      model: '',
      id: `AST-${Math.floor(Math.random() * 9000) + 1000}`,
      observations: `Item recebido via Pedido de Compra referente à requisição ${currentRequest?.id}`,
      type: currentFulfillment.type
    });
    setShowReceiptForm(true);
  };

  const handleFinalizeAndCreateAsset = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentRequest || activeSelection === null || !currentFulfillment) return;

    // 1. Cria o ativo no inventário
    onAssetCreated({
      id: receiptData.id || '',
      brand: receiptData.brand || '',
      model: receiptData.model || '',
      type: currentFulfillment.type,
      status: 'Em Uso',
      assignedTo: currentRequest.employeeId,
      observations: receiptData.observations || '',
      photos: []
    });

    // 2. Atualiza o status da requisição para entregue
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { 
      ...newFulfillments[activeSelection.fIndex], 
      isDelivered: true,
      linkedAssetId: receiptData.id 
    };

    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });

    // 3. Limpa estados
    setShowReceiptForm(false);
    setActiveSelection(null);
  };

  const handleSetDeliveryForecast = (date: string) => {
    if (!currentRequest || activeSelection === null) return;
    const newFulfillments = [...(currentRequest.itemFulfillments || [])];
    newFulfillments[activeSelection.fIndex] = { ...newFulfillments[activeSelection.fIndex], deliveryForecastDate: date };
    onUpdateRequest({ ...currentRequest, itemFulfillments: newFulfillments });
  };

  const toggleBulk = (id: string) => {
    setBulkSelected(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Stats Summary */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cotações Pendentes', count: purchaseItems.filter(i => (i.fulfillment.purchaseStatus || 'Pendente') === 'Pendente').length, color: 'amber' },
          { label: 'Aguard. Autorização', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Cotação Aprovada').length, color: 'blue' },
          { label: 'Pedidos Autorizados', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Pedido Autorizado').length, color: 'indigo' },
          { label: 'Em Trânsito (Pagos)', count: purchaseItems.filter(i => i.fulfillment.purchaseStatus === 'Comprado').length, color: 'emerald' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</p>
            <p className={`text-3xl font-black text-${stat.color}-600 tracking-tight`}>{stat.count}</p>
          </div>
        ))}
      </div>

      {/* Bulk Actions Bar */}
      {bulkSelected.length > 0 && (
        <div className="bg-slate-900 text-white p-6 rounded-[2rem] flex items-center justify-between shadow-2xl animate-in slide-in-from-top-4">
           <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center">
                 <ShoppingCart className="w-5 h-5 text-blue-400" />
              </div>
              <div>
                 <p className="font-bold">{bulkSelected.length} itens selecionados</p>
                 <p className="text-xs text-slate-400">Você pode processar a compra conjunta destes itens agora.</p>
              </div>
           </div>
           <div className="flex gap-3">
              <button onClick={() => setBulkSelected([])} className="px-6 py-2.5 rounded-xl font-bold text-slate-400 hover:text-white transition-colors">Cancelar</button>
              <button 
                onClick={handleBulkMarkAsPurchased}
                className="bg-blue-600 hover:bg-blue-700 px-8 py-2.5 rounded-xl font-bold shadow-lg flex items-center gap-2"
              >
                <CreditCard className="w-4 h-4" /> Confirmar Pagamento do Lote
              </button>
           </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar por item ou colaborador..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm bg-white font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex bg-white p-1.5 rounded-2xl border border-slate-100 shadow-sm overflow-x-auto max-w-full">
          {['Todos', 'Pendente', 'Cotação Aprovada', 'Pedido Autorizado', 'Comprado'].map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${
                statusFilter === status 
                  ? 'bg-slate-900 text-white shadow-lg' 
                  : 'text-slate-500 hover:bg-slate-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/50 border-b border-slate-100">
              <th className="px-6 py-5 w-12 text-center">
                 <div className="flex items-center justify-center">
                    <MoreHorizontal className="w-4 h-4 text-slate-300" />
                 </div>
              </th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipamento</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status Atual</th>
              <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ação</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredItems.map((item) => {
              const itemId = `${item.request.id}-${item.index}`;
              const isAutorizado = item.fulfillment.purchaseStatus === 'Pedido Autorizado';
              const isSelected = bulkSelected.includes(itemId);

              return (
                <tr 
                  key={itemId} 
                  className={`hover:bg-slate-50/50 transition-colors group cursor-pointer ${isSelected ? 'bg-blue-50/30' : ''}`}
                  onClick={() => setActiveSelection({ requestId: item.request.id, fIndex: item.index })}
                >
                  <td className="px-6 py-6 text-center" onClick={(e) => e.stopPropagation()}>
                    {isAutorizado ? (
                      <button onClick={() => toggleBulk(itemId)}>
                        {isSelected ? <CheckSquare className="w-5 h-5 text-blue-600" /> : <Square className="w-5 h-5 text-slate-200" />}
                      </button>
                    ) : (
                      <div className="w-5 h-5" />
                    )}
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                        <Package className="w-5 h-5" />
                      </div>
                      <span className="font-bold text-slate-800">{item.fulfillment.type}</span>
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    <p className="text-sm font-bold text-slate-700">{getEmployeeName(item.request.employeeId)}</p>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest border ${
                      (item.fulfillment.purchaseStatus || 'Pendente') === 'Pendente' ? 'bg-amber-50 text-amber-600 border-amber-200' :
                      item.fulfillment.purchaseStatus === 'Cotação Aprovada' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                      item.fulfillment.purchaseStatus === 'Pedido Autorizado' ? 'bg-indigo-50 text-indigo-600 border-indigo-200' :
                      'bg-emerald-600 text-white border-emerald-700'
                    }`}>
                      {item.fulfillment.purchaseStatus || 'Pendente'}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <ChevronRight className="w-5 h-5 text-slate-300 ml-auto group-hover:translate-x-1 transition-transform" />
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>

        {filteredItems.length === 0 && (
          <div className="p-20 text-center flex flex-col items-center">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-4">
                <ShoppingCart className="w-10 h-10 text-slate-200" />
             </div>
             <p className="text-slate-400 font-bold">Nenhum pedido encontrado para o filtro selecionado.</p>
          </div>
        )}
      </div>

      {/* Side Details Panel */}
      {activeSelection && currentRequest && currentFulfillment && (
        <div className="fixed inset-0 z-[100] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setActiveSelection(null)} />
          <div className="relative w-full max-w-2xl bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
             <div className="p-8 border-b border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100">
                    <ShoppingCart className="w-7 h-7" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-slate-800">Workflow de Compra</h3>
                    <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{currentRequest.id} • {currentFulfillment.type}</p>
                  </div>
                </div>
                <button onClick={() => setActiveSelection(null)} className="p-3 hover:bg-slate-100 rounded-full transition-colors">
                  <X className="w-6 h-6 text-slate-400" />
                </button>
             </div>

             <div className="flex-1 overflow-y-auto p-8 space-y-10">
                {/* Status Progress Map */}
                <div className="flex items-center justify-between px-4">
                   {['Cotação', 'Aprovação', 'Autorização', 'Compra'].map((step, idx) => (
                     <div key={idx} className="flex flex-col items-center gap-2">
                        <div className={`w-3 h-3 rounded-full ${
                          (idx === 0) || 
                          (idx === 1 && currentFulfillment.purchaseStatus !== 'Pendente') ||
                          (idx === 2 && ['Pedido Autorizado', 'Comprado'].includes(currentFulfillment.purchaseStatus!)) ||
                          (idx === 3 && currentFulfillment.purchaseStatus === 'Comprado')
                            ? 'bg-blue-600' : 'bg-slate-200'
                        }`} />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{step}</span>
                     </div>
                   ))}
                </div>

                {/* Section 1: Cotações */}
                <div className="space-y-6">
                   <div className="flex items-center justify-between">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <FileText className="w-4 h-4 text-blue-600" /> Comparativo de Mercado
                      </h4>
                      {(currentFulfillment.purchaseStatus || 'Pendente') === 'Pendente' && (
                        <span className="text-[10px] text-amber-600 bg-amber-50 px-3 py-1 rounded-lg border border-amber-200 font-bold uppercase">Preencher cotações</span>
                      )}
                   </div>

                   <div className="space-y-4">
                      {[0, 1, 2].map(qIdx => {
                        const q = currentFulfillment.quotations?.[qIdx] || { url: '', deliveryPrediction: '' };
                        const isChosen = currentFulfillment.approvedQuotationIndex === qIdx;
                        const canEdit = (currentFulfillment.purchaseStatus || 'Pendente') === 'Pendente';

                        return (
                          <div key={qIdx} className={`p-6 rounded-[2.5rem] border transition-all ${
                            isChosen ? 'bg-blue-50 border-blue-200' : 'bg-slate-50 border-slate-100'
                          }`}>
                            <div className="flex items-center justify-between mb-4">
                               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Opção de Fornecedor 0{qIdx + 1}</span>
                               {isChosen && <span className="bg-blue-600 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase">Cotação Selecionada</span>}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                               <div className="space-y-1">
                                  <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">URL / Link</label>
                                  <div className="relative">
                                    <LinkIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                                    <input 
                                      className="w-full pl-10 pr-4 py-3 rounded-2xl border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white font-medium"
                                      placeholder="Link do produto..."
                                      value={q.url}
                                      onChange={(e) => handleUpdateQuotation(qIdx, 'url', e.target.value)}
                                      disabled={!canEdit}
                                    />
                                  </div>
                               </div>
                               <div className="space-y-1">
                                  <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Entrega Est.</label>
                                  <input 
                                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 text-sm focus:ring-2 focus:ring-blue-500 outline-none bg-white font-medium"
                                    placeholder="Ex: 3 dias"
                                    value={q.deliveryPrediction}
                                    onChange={(e) => handleUpdateQuotation(qIdx, 'deliveryPrediction', e.target.value)}
                                    disabled={!canEdit}
                                  />
                               </div>
                            </div>

                            {canEdit && q.url && q.deliveryPrediction && (
                              <button 
                                onClick={() => handleApproveQuotation(qIdx)}
                                className="mt-4 w-full bg-white border border-slate-200 py-3 rounded-2xl text-xs font-black text-slate-700 hover:bg-slate-900 hover:text-white transition-all shadow-sm flex items-center justify-center gap-2 uppercase tracking-widest"
                              >
                                <Check className="w-4 h-4" /> Selecionar Fornecedor
                              </button>
                            )}
                          </div>
                        );
                      })}
                   </div>
                </div>

                {/* Section 2: Autorização */}
                {currentFulfillment.purchaseStatus === 'Cotação Aprovada' && (
                  <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white space-y-4 shadow-xl shadow-indigo-100 animate-in zoom-in-95">
                     <div className="flex items-center gap-3">
                        <ShieldCheck className="w-6 h-6" />
                        <h4 className="font-black uppercase tracking-widest text-sm">Autorização de Pedido</h4>
                     </div>
                     <p className="text-sm text-indigo-100 leading-relaxed">
                        A cotação foi selecionada com sucesso. Agora o gestor responsável deve autorizar o pedido para que o financeiro proceda com o pagamento.
                     </p>
                     <button 
                        onClick={handleAuthorizeOrder}
                        className="w-full bg-white text-indigo-600 font-black py-4 rounded-2xl shadow-lg hover:bg-indigo-50 transition-all uppercase tracking-widest flex items-center justify-center gap-2"
                     >
                        <Zap className="w-5 h-5" /> Autorizar Pedido Agora
                     </button>
                  </div>
                )}

                {/* Section 3: Pagamento (Status Pedido Autorizado) */}
                {currentFulfillment.purchaseStatus === 'Pedido Autorizado' && (
                  <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white space-y-4 shadow-2xl">
                     <div className="flex items-center gap-3">
                        <CreditCard className="w-6 h-6 text-blue-400" />
                        <h4 className="font-black uppercase tracking-widest text-sm">Liquidação de Pedido</h4>
                     </div>
                     <p className="text-sm text-slate-400 leading-relaxed">
                        Este pedido está autorizado. Você pode marcá-lo como pago individualmente aqui ou fechar um lote na tela principal.
                     </p>
                     <button 
                        onClick={() => handleSetComprado(currentRequest.id, activeSelection.fIndex)}
                        className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest flex items-center justify-center gap-2"
                     >
                        Confirmar Pagamento Realizado
                     </button>
                  </div>
                )}

                {/* Section 4: Entrega (Status Comprado) */}
                {currentFulfillment.purchaseStatus === 'Comprado' && (
                  <div className="space-y-6 animate-in slide-in-from-bottom-4">
                     <div className="p-8 bg-emerald-600 rounded-[2.5rem] text-white space-y-6 shadow-xl">
                        <div className="flex items-center gap-3">
                           <Truck className="w-6 h-6" />
                           <h4 className="font-black uppercase tracking-widest text-sm">Acompanhamento Logístico</h4>
                        </div>

                        <div className="space-y-2">
                           <label className="text-[10px] font-black text-emerald-200 uppercase tracking-widest ml-1">Data Prevista de Chegada</label>
                           <input 
                            type="date"
                            className="w-full bg-emerald-700/50 border border-emerald-500 rounded-2xl p-4 text-white focus:ring-2 focus:ring-white outline-none font-bold"
                            value={currentFulfillment.deliveryForecastDate || ''}
                            onChange={(e) => handleSetDeliveryForecast(e.target.value)}
                           />
                        </div>

                        <div className="p-4 bg-white/10 rounded-2xl flex items-start gap-3">
                           <AlertCircle className="w-5 h-5 text-emerald-200 shrink-0" />
                           <p className="text-[10px] text-emerald-50 font-bold leading-relaxed uppercase">
                             O item permanecerá no dashboard até que o TI confirme o recebimento e o número de série.
                           </p>
                        </div>

                        <button 
                          onClick={handleOpenReceipt}
                          className="w-full bg-white text-emerald-600 font-black py-4 rounded-2xl shadow-xl hover:bg-emerald-50 transition-all uppercase tracking-widest flex items-center justify-center gap-2"
                        >
                          <Tag className="w-5 h-5" /> Confirmar Entrega e Cadastrar Patrimônio
                        </button>
                     </div>
                  </div>
                )}
             </div>
          </div>
        </div>
      )}

      {/* Modal de Recebimento e Tombamento (Cadastro no Inventário) */}
      {showReceiptForm && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
              <div className="bg-emerald-600 p-8 text-white flex items-center justify-between">
                 <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center">
                       <QrCode className="w-7 h-7" />
                    </div>
                    <div>
                       <h3 className="text-xl font-black tracking-tight">Entrada de Patrimônio</h3>
                       <p className="text-emerald-100 text-xs font-bold uppercase tracking-widest">Recebimento de Item de Compra</p>
                    </div>
                 </div>
                 <button onClick={() => setShowReceiptForm(false)} className="p-2 hover:bg-white/10 rounded-full">
                    <X className="w-6 h-6" />
                 </button>
              </div>

              <form onSubmit={handleFinalizeAndCreateAsset} className="p-10 space-y-6">
                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Patrimonial (Automático)</label>
                       <input 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-mono font-bold text-slate-800"
                        value={receiptData.id}
                        onChange={e => setReceiptData({...receiptData, id: e.target.value})}
                        required
                       />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Equipamento</label>
                       <input 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 font-bold text-slate-500"
                        value={receiptData.type}
                        disabled
                       />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-6">
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Marca Recebida</label>
                       <input 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                        placeholder="Ex: Dell, Apple, LG..."
                        value={receiptData.brand}
                        onChange={e => setReceiptData({...receiptData, brand: e.target.value})}
                        required
                       />
                    </div>
                    <div className="space-y-1.5">
                       <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Modelo Exato</label>
                       <input 
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-emerald-500 outline-none font-bold"
                        placeholder="Ex: Latitude 5430"
                        value={receiptData.model}
                        onChange={e => setReceiptData({...receiptData, model: e.target.value})}
                        required
                       />
                    </div>
                 </div>

                 <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Notas de Recebimento / Serial Number</label>
                    <textarea 
                      className="w-full p-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-emerald-500 outline-none resize-none h-24 font-medium text-slate-600"
                      placeholder="Insira o número de série e observações técnicas..."
                      value={receiptData.observations}
                      onChange={e => setReceiptData({...receiptData, observations: e.target.value})}
                    />
                 </div>

                 <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100 flex items-start gap-4">
                    <AlertCircle className="w-6 h-6 text-emerald-600 shrink-0" />
                    <div>
                       <p className="text-xs font-bold text-emerald-800 leading-tight">Ao confirmar, o item será vinculado automaticamente a {getEmployeeName(currentRequest?.employeeId || '')}.</p>
                       <p className="text-[10px] text-emerald-600 mt-1 uppercase font-black">Uma etiqueta patrimonial será gerada no módulo de impressões.</p>
                    </div>
                 </div>

                 <button 
                  type="submit"
                  className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-[2rem] shadow-xl shadow-emerald-100 transition-all flex items-center justify-center gap-3 uppercase tracking-widest"
                 >
                    <Check className="w-6 h-6" /> Finalizar e Gerar Patrimônio
                 </button>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default PurchaseOrderManager;

import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import UserManager from './components/UserManager';
import Auth from './components/Auth';
import { MOCK_ASSETS, MOCK_EMPLOYEES, MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, AppModule } from './types';
import { Package, Camera, CheckCircle2, X, RefreshCw, ShieldCheck, AlertCircle, ClipboardList } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');

  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [users, setUsers] = useState<UserAccount[]>(MOCK_USERS);
  const [isAuditing, setIsAuditing] = useState(false);
  const [auditProgress, setAuditProgress] = useState<string[]>([]); // IDs dos ativos já auditados nesta sessão

  const videoRef = useRef<HTMLVideoElement>(null);

  const [requests, setRequests] = useState<EquipmentRequest[]>([
    {
      id: 'REQ-1',
      requesterId: '2',
      employeeId: '1',
      items: ['Notebook', 'Mouse', 'Monitor'],
      itemFulfillments: [
        { type: 'Notebook', isPurchaseOrder: true, purchaseStatus: 'Pendente' },
        { type: 'Mouse', isPurchaseOrder: false },
        { type: 'Monitor', isPurchaseOrder: false }
      ],
      status: 'Pendente',
      createdAt: '2024-03-20',
      observation: 'Colaborador novo iniciando na próxima segunda-feira. Necessita de setup completo.'
    }
  ]);

  useEffect(() => {
    if (currentUser && !currentUser.modules.includes(activeTab as AppModule)) {
      if (currentUser.modules.length > 0) {
        setActiveTab(currentUser.modules[0]);
      }
    }
  }, [currentUser, activeTab]);

  // Gerenciamento de Câmera para Auditoria
  useEffect(() => {
    let stream: MediaStream | null = null;
    if (isAuditing && videoRef.current) {
      navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
        .then(s => {
          stream = s;
          if (videoRef.current) videoRef.current.srcObject = s;
        })
        .catch(err => console.error("Erro ao acessar câmera:", err));
    }
    return () => {
      if (stream) stream.getTracks().forEach(track => track.stop());
    };
  }, [isAuditing]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
    setIsAuditing(false);
  };

  const handleAddAsset = (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      id: assetData.id || `AST-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${Math.random().toString(36).substr(2, 9)}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleAssetCreatedFromPurchase = (assetData: Omit<Asset, 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${assetData.id}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleUpdateAsset = (updatedAsset: Asset) => {
    setAssets(assets.map(a => a.id === updatedAsset.id ? updatedAsset : a));
  };

  const handleAddEmployee = (empData: Omit<Employee, 'id'>) => {
    const newEmp: Employee = { ...empData, id: String(employees.length + 1) };
    setEmployees([newEmp, ...employees]);
  };

  const handleAddUser = (userData: Omit<UserAccount, 'id'>) => {
    const newUser: UserAccount = { ...userData, id: String(Date.now()) };
    setUsers([...users, newUser]);
  };

  const handleUpdateUser = (updatedUser: UserAccount) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (currentUser?.id === updatedUser.id) setCurrentUser(updatedUser);
  };

  const handleAddRequest = (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const newReq: EquipmentRequest = {
      ...reqData,
      id: `REQ-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      status: 'Pendente',
      createdAt: new Date().toLocaleDateString('pt-BR'),
      itemFulfillments: reqData.items.map(type => ({ type, isPurchaseOrder: false }))
    };
    setRequests([newReq, ...requests]);
  };

  const handleUpdateStatus = (id: string, status: EquipmentRequest['status']) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status } : r));
  };

  const handleUpdateRequest = (updatedReq: EquipmentRequest) => {
    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const simulateScan = () => {
    const pending = assets.filter(a => !auditProgress.includes(a.id));
    if (pending.length > 0) {
      const randomAsset = pending[Math.floor(Math.random() * pending.length)];
      setAuditProgress(prev => [...prev, randomAsset.id]);
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} />;
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={(id) => setAssets(assets.filter(a => a.id !== id))} 
          />
        );
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      case 'requests':
        return (
          <RequestsManager 
            requests={requests} 
            employees={employees} 
            assets={assets}
            onAddRequest={handleAddRequest} 
            onUpdateStatus={handleUpdateStatus}
            onUpdateRequest={handleUpdateRequest}
          />
        );
      case 'purchase-orders':
        return (
          <PurchaseOrderManager 
            requests={requests} 
            employees={employees}
            onUpdateRequest={handleUpdateRequest}
            onAssetCreated={handleAssetCreatedFromPurchase}
          />
        );
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'user-management':
        return (
          <UserManager 
            users={users} 
            onAddUser={handleAddUser}
            onUpdateUser={handleUpdateUser}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        );
      case 'inventory-check':
        if (isAuditing) {
          return (
            <div className="space-y-8 animate-in zoom-in-95 duration-300">
              <div className="flex items-center justify-between">
                <div>
                   <h3 className="text-2xl font-black text-slate-800 tracking-tight">Sessão de Auditoria Ativa</h3>
                   <p className="text-slate-500 font-medium">Escaneie as etiquetas QR para validar a presença física dos ativos.</p>
                </div>
                <button 
                  onClick={() => { setIsAuditing(false); setAuditProgress([]); }}
                  className="flex items-center gap-2 px-4 py-2 bg-rose-50 text-rose-600 rounded-xl font-bold hover:bg-rose-100 transition-colors"
                >
                  <X className="w-4 h-4" /> Finalizar Sem Salvar
                </button>
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Visor do Scanner */}
                <div className="lg:col-span-2 space-y-4">
                  <div className="relative aspect-video bg-black rounded-[2.5rem] overflow-hidden shadow-2xl border-4 border-slate-900 group">
                    <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-60" />

                    {/* Moldura de Foco */}
                    <div className="absolute inset-0 flex items-center justify-center">
                      <div className="w-64 h-64 border-2 border-blue-500/50 rounded-3xl relative">
                        <div className="absolute -top-1 -left-1 w-8 h-8 border-t-4 border-l-4 border-blue-500 rounded-tl-xl" />
                        <div className="absolute -top-1 -right-1 w-8 h-8 border-t-4 border-r-4 border-blue-500 rounded-tr-xl" />
                        <div className="absolute -bottom-1 -left-1 w-8 h-8 border-b-4 border-l-4 border-blue-500 rounded-bl-xl" />
                        <div className="absolute -bottom-1 -right-1 w-8 h-8 border-b-4 border-r-4 border-blue-500 rounded-br-xl" />

                        {/* Linha de Scanner Animada */}
                        <div className="absolute left-0 right-0 h-0.5 bg-blue-400 shadow-[0_0_15px_rgba(59,130,246,0.8)] animate-scan shadow-blue-500" />
                      </div>
                    </div>

                    <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-3">
                       <button 
                        onClick={simulateScan}
                        className="bg-white/90 backdrop-blur px-8 py-3 rounded-2xl font-black text-slate-900 flex items-center gap-2 hover:bg-white transition-all shadow-xl"
                       >
                         <Camera className="w-5 h-5 text-blue-600" /> Simular Leitura
                       </button>
                    </div>

                    <div className="absolute top-6 left-6 bg-slate-900/80 backdrop-blur px-4 py-2 rounded-xl border border-white/10 flex items-center gap-2">
                       <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                       <span className="text-[10px] font-bold text-white uppercase tracking-widest">Câmera Ativa</span>
                    </div>
                  </div>

                  <div className="bg-blue-600 p-6 rounded-[2rem] text-white flex items-center justify-between shadow-xl shadow-blue-200">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center">
                        <RefreshCw className="w-6 h-6 animate-spin-slow" />
                      </div>
                      <div>
                        <p className="text-xs font-bold text-blue-100 uppercase tracking-widest leading-tight">Progresso da Auditoria</p>
                        <p className="text-xl font-black leading-tight">{Math.round((auditProgress.length / assets.length) * 100)}% Concluído</p>
                      </div>
                    </div>
                    <div className="flex-1 max-w-xs mx-8 h-3 bg-white/20 rounded-full overflow-hidden">
                       <div 
                        className="h-full bg-white transition-all duration-500" 
                        style={{ width: `${(auditProgress.length / assets.length) * 100}%` }} 
                       />
                    </div>
                    <button 
                      onClick={() => { setIsAuditing(false); setAuditProgress([]); }}
                      disabled={auditProgress.length === 0}
                      className={`px-8 py-3 rounded-xl font-bold transition-all ${
                        auditProgress.length > 0 ? 'bg-white text-blue-600 shadow-lg' : 'bg-white/10 text-white/40 cursor-not-allowed'
                      }`}
                    >
                      Salvar Relatório
                    </button>
                  </div>
                </div>

                {/* Sidebar de Status da Sessão */}
                <div className="space-y-6">
                   <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <CheckCircle2 className="w-4 h-4 text-emerald-500" /> Verificados ({auditProgress.length})
                      </h4>
                      <div className="space-y-2 max-h-48 overflow-y-auto pr-2 custom-scrollbar">
                         {auditProgress.map(id => {
                           const asset = assets.find(a => a.id === id);
                           return (
                             <div key={id} className="p-3 bg-emerald-50 rounded-xl border border-emerald-100 flex items-center justify-between">
                                <div>
                                  <p className="text-xs font-bold text-emerald-800">{id}</p>
                                  <p className="text-[10px] text-emerald-600">{asset?.brand} {asset?.model}</p>
                                </div>
                                <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                             </div>
                           );
                         })}
                         {auditProgress.length === 0 && <p className="text-xs text-slate-400 italic text-center py-4">Nenhum item escaneado.</p>}
                      </div>
                   </div>

                   <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4">
                      <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                        <AlertCircle className="w-4 h-4 text-amber-500" /> Pendentes ({assets.length - auditProgress.length})
                      </h4>
                      <div className="space-y-2 max-h-64 overflow-y-auto pr-2 custom-scrollbar">
                         {assets.filter(a => !auditProgress.includes(a.id)).map(asset => (
                           <div key={asset.id} className="p-3 bg-slate-50 rounded-xl border border-slate-100">
                              <p className="text-xs font-bold text-slate-700">{asset.id}</p>
                              <p className="text-[10px] text-slate-500">{asset.brand} {asset.model}</p>
                           </div>
                         ))}
                      </div>
                   </div>
                </div>
              </div>

              <style>{`
                @keyframes scan {
                  0%, 100% { top: 0%; }
                  50% { top: 100%; }
                }
                .animate-scan {
                  animation: scan 3s ease-in-out infinite;
                }
                .animate-spin-slow {
                  animation: spin 3s linear infinite;
                }
              `}</style>
            </div>
          );
        }

        return (
          <div className="flex flex-col items-center justify-center py-20 text-center space-y-4 animate-in fade-in duration-700">
            <div className="w-20 h-20 bg-blue-100 rounded-[2rem] flex items-center justify-center text-blue-600 shadow-xl shadow-blue-100/50 transform hover:scale-110 transition-transform">
              <ClipboardList className="w-10 h-10" />
            </div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">Verificação Semestral</h3>
            <p className="text-slate-500 max-w-md font-medium">
              A auditoria geral de ativos valida o estado físico e a localização de cada equipamento da empresa.
            </p>
            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm max-w-sm w-full my-6 text-left">
               <div className="flex items-center gap-3 mb-4 text-emerald-600">
                  <ShieldCheck className="w-5 h-5" />
                  <span className="text-xs font-black uppercase tracking-widest">Protocolo Seguro</span>
               </div>
               <ul className="text-xs text-slate-500 space-y-3 font-medium">
                  <li className="flex items-center gap-2">
                    <div className="w-1 h-1 bg-blue-500 rounded-full" /> Localize a etiqueta QR no ativo
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1 h-1 bg-blue-500 rounded-full" /> Use a câmera para validar
                  </li>
                  <li className="flex items-center gap-2">
                    <div className="w-1 h-1 bg-blue-500 rounded-full" /> Registre divergências técnicas
                  </li>
               </ul>
            </div>
            <button 
              onClick={() => setIsAuditing(true)}
              className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black shadow-2xl shadow-slate-200 hover:bg-black transition-all mt-4 transform active:scale-95"
            >
              Iniciar Auditoria de Campo
            </button>
          </div>
        );
      default:
        return <div className="p-20 text-center text-slate-400">Carregando módulo...</div>;
    }
  };

  if (!isAuthenticated || !currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser}
      onLogout={handleLogout}
    >
      {renderContent()}
    </Layout>
  );
};

