import { ASSET_TYPES } from '../constants';

interface AssetManagerProps {
  assets: Asset[];
  employees: Employee[];
  companies: Company[];
  onAdd: (asset: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => void;
  onUpdate: (asset: Asset) => void;
  onRemove: (id: string) => void;
}

const AssetManager: React.FC<AssetManagerProps> = ({ assets, employees, companies, onAdd, onUpdate, onRemove }) => {
  const [showForm, setShowForm] = useState(false);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [filterCompany, setFilterCompany] = useState<string>('all');
  const [filterAvailability, setFilterAvailability] = useState<string>('all');
  const [isPrinting, setIsPrinting] = useState(false);

  const [newAsset, setNewAsset] = useState<Partial<Asset>>({
    type: 'Notebook',
    status: 'Pendente Documentos',
    photos: [],
    companyId: companies[0]?.id || ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newAsset.companyId) {
      alert("Por favor, selecione a empresa proprietária.");
      return;
    }
    onAdd(newAsset as Omit<Asset, 'id' | 'createdAt' | 'qrCode'>);
    setShowForm(false);
    setNewAsset({ type: 'Notebook', status: 'Pendente Documentos', photos: [], companyId: companies[0]?.id || '' });
  };

  const handleUpdateDetail = (updates: Partial<Asset>) => {
    if (!selectedAsset) return;
    const updated = { ...selectedAsset, ...updates };
    setSelectedAsset(updated);
    onUpdate(updated);
  };

  const handleAddPhoto = () => {
    const newPhotoUrl = `https://picsum.photos/400/300?random=${Math.random()}`;
    if (selectedAsset) {
      handleUpdateDetail({ photos: [...selectedAsset.photos, newPhotoUrl] });
    }
  };

  const handleRemovePhoto = (index: number) => {
    if (selectedAsset) {
      const newPhotos = selectedAsset.photos.filter((_, i) => i !== index);
      handleUpdateDetail({ photos: newPhotos });
    }
  };

