import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Package, 
  Users, 
  FileText, 
  Menu, 
  X, 
  LogOut,
  ClipboardList,
  Printer,
  ShoppingCart,
  ShieldCheck,
