import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import CompanyManager from './components/CompanyManager';
import Auth from './components/Auth';
import { MOCK_ASSETS, MOCK_EMPLOYEES, MOCK_USERS, MOCK_COMPANIES } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, AppModule, AuditSession, Company } from './types';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');

  const [companies, setCompanies] = useState<Company[]>(MOCK_COMPANIES);
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [users, setUsers] = useState<UserAccount[]>(MOCK_USERS);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  const [requests, setRequests] = useState<EquipmentRequest[]>([
    {
      id: 'REQ-1',
      requesterId: '2',
      employeeId: '1',
      items: ['Notebook', 'Mouse', 'Monitor'],
      itemFulfillments: [
        { type: 'Notebook', isPurchaseOrder: true, purchaseStatus: 'Pendente' },
        { type: 'Mouse', isPurchaseOrder: false },
        { type: 'Monitor', isPurchaseOrder: false }
      ],
      status: 'Pendente',
      createdAt: '2024-03-20',
      observation: 'Colaborador novo iniciando na próxima segunda-feira. Necessita de setup completo.'
    }
  ]);

  useEffect(() => {
    if (currentUser && !currentUser.modules.includes(activeTab as AppModule)) {
      if (currentUser.modules.length > 0) {
        setActiveTab(currentUser.modules[0]);
      }
    }
  }, [currentUser, activeTab]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddCompany = (compData: Omit<Company, 'id' | 'createdAt'>) => {
    const newCompany: Company = {
      ...compData,
      id: `COMP-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR')
    };
    setCompanies([...companies, newCompany]);
  };

  const handleAddAsset = (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      id: `AST-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${Math.random().toString(36).substr(2, 9)}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleAssetCreatedFromPurchase = (assetData: Omit<Asset, 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${assetData.id}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleUpdateAsset = (updatedAsset: Asset) => {
    setAssets(assets.map(a => a.id === updatedAsset.id ? updatedAsset : a));
  };

  const handleAddEmployee = (empData: Omit<Employee, 'id'>) => {
    const newEmp: Employee = { ...empData, id: String(employees.length + 1) };
    setEmployees([newEmp, ...employees]);
  };

  const handleAddRequest = (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const newReq: EquipmentRequest = {
      ...reqData,
      id: `REQ-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      status: 'Pendente',
      createdAt: new Date().toLocaleDateString('pt-BR'),
      itemFulfillments: reqData.items.map(type => ({ type, isPurchaseOrder: false }))
    };
    setRequests([newReq, ...requests]);
  };

  const handleUpdateStatus = (id: string, status: EquipmentRequest['status']) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status } : r));
  };

  const handleUpdateRequest = (updatedReq: EquipmentRequest) => {
    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return (
          <CompanyManager 
            companies={companies} 
            assets={assets}
            onAddCompany={handleAddCompany}
            onRemoveCompany={(id) => setCompanies(companies.filter(c => c.id !== id))}
          />
        );
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            companies={companies}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={(id) => setAssets(assets.filter(a => a.id !== id))} 
          />
        );
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      case 'requests':
        return (
          <RequestsManager 
            requests={requests} 
            employees={employees} 
            assets={assets}
            onAddRequest={handleAddRequest} 
            onUpdateStatus={handleUpdateStatus}
            onUpdateRequest={handleUpdateRequest}
          />
        );
      case 'purchase-orders':
        return (
          <PurchaseOrderManager 
            requests={requests} 
            employees={employees}
            onUpdateRequest={handleUpdateRequest}
            onAssetCreated={handleAssetCreatedFromPurchase}
          />
        );
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'user-management':
        return (
          <UserManager 
            users={users} 
            onAddUser={(u) => setUsers([...users, {...u, id: String(Date.now())}])}
            onUpdateUser={(u) => setUsers(users.map(old => old.id === u.id ? u : old))}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        );
      case 'inventory-check':
        return (
          <InventoryCheckManager 
            assets={assets}
            employees={employees}
            auditSessions={auditSessions}
            onAddAuditSession={(s) => setAuditSessions([...auditSessions, s])}
            onUpdateAuditSession={(s) => setAuditSessions(auditSessions.map(old => old.id === s.id ? s : old))}
            onGenerateDivergenceRequest={() => {}} // Lógica implementada conforme anterior
          />
        );
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo em Desenvolvimento</div>;
    }
  };

  if (!isAuthenticated || !currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser}
      onLogout={handleLogout}
      requests={requests}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  Printer, 
  Search, 
  Filter, 
  CheckCircle2, 
  AlertTriangle, 
  X, 
  ClipboardList, 
  FileText, 
  ArrowRight,
  Plus,
  Trash2,
  Check,
  ChevronRight,
  User,
  Package,
  AlertCircle
} from 'lucide-react';
import { Asset, Employee, AuditSession, AuditStatus, AuditEntry, EquipmentRequest } from '../types';

interface InventoryCheckManagerProps {
  assets: Asset[];
  employees: Employee[];
  auditSessions: AuditSession[];
  onAddAuditSession: (session: AuditSession) => void;
  onUpdateAuditSession: (session: AuditSession) => void;
  onGenerateDivergenceRequest: (sector: string, assets: string[]) => void;
}

const InventoryCheckManager: React.FC<InventoryCheckManagerProps> = ({ 
  assets, 
  employees, 
  auditSessions, 
  onAddAuditSession, 
  onUpdateAuditSession,
  onGenerateDivergenceRequest
}) => {
  const [activeView, setActiveView] = useState<'list' | 'create' | 'entry'>('list');
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);
  const [selectedSector, setSelectedSector] = useState<string>('');

  const sectors = useMemo(() => Array.from(new Set(employees.map(e => e.sector))), [employees]);

  const selectedSession = useMemo(() => 
    auditSessions.find(s => s.id === selectedSessionId) || null
  , [auditSessions, selectedSessionId]);

  const handleCreateSession = () => {
    if (!selectedSector) return;

    const newSession: AuditSession = {
      id: `AUD-${Date.now()}`,
      sector: selectedSector,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      entries: [],
      isFinished: false
    };

    onAddAuditSession(newSession);
    setSelectedSessionId(newSession.id);
    setActiveView('entry');
  };

  const assetsInSector = useMemo(() => {
    const currentSector = selectedSession ? selectedSession.sector : selectedSector;
    if (!currentSector) return [];

    const employeesInSector = employees.filter(e => e.sector === currentSector).map(e => e.id);
    return assets.filter(a => a.assignedTo && employeesInSector.includes(a.assignedTo));
  }, [assets, employees, selectedSector, selectedSession]);

  const handleUpdateEntry = (assetId: string, status: AuditStatus) => {
    if (!selectedSession) return;

    const newEntries = [...selectedSession.entries];
    const existingIndex = newEntries.findIndex(e => e.assetId === assetId);

    if (existingIndex >= 0) {
      newEntries[existingIndex] = { ...newEntries[existingIndex], status, checkedAt: new Date().toISOString() };
    } else {
      newEntries.push({ assetId, status, checkedAt: new Date().toISOString() });
    }

    onUpdateAuditSession({ ...selectedSession, entries: newEntries });
  };

  const handleFinishAudit = () => {
    if (!selectedSession) return;

    const issues = selectedSession.entries.filter(e => e.status === 'Ruim' || e.status === 'Não Encontrado');
    const updatedSession = { ...selectedSession, isFinished: true };

    onUpdateAuditSession(updatedSession);

    if (issues.length > 0) {
      const assetIds = issues.map(i => i.assetId);
      onGenerateDivergenceRequest(selectedSession.sector, assetIds);
      alert(`${issues.length} divergências encontradas! Um pedido de confronto foi gerado para o setor ${selectedSession.sector}.`);
    } else {
      alert('Auditoria concluída com sucesso! Nenhuma divergência encontrada.');
    }

    setActiveView('list');
    setSelectedSessionId(null);
  };

  const handlePrintSheet = () => {
    window.print();
  };

  const getEmployeeName = (id?: string) => employees.find(e => e.id === id)?.name || 'N/A';

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* UI SECTION: Only visible on screen */}
      <div className="print:hidden space-y-8">
        {activeView === 'list' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h3 className="text-2xl font-black text-slate-800 tracking-tight">Check Semestral</h3>
                <p className="text-slate-500 font-medium">Gestão de auditorias de ativos por setor.</p>
              </div>
              <button 
                onClick={() => setActiveView('create')}
                className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95"
              >
                <Plus className="w-5 h-5" />
                Nova Auditoria
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {auditSessions.map(session => (
                <div 
                  key={session.id} 
                  className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all cursor-pointer group flex flex-col"
                  onClick={() => {
                    setSelectedSessionId(session.id);
                    setActiveView('entry');
                  }}
                >
                  <div className="flex justify-between items-start mb-4">
                    <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-500 transition-colors">
                      <ClipboardList className="w-6 h-6" />
                    </div>
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                      session.isFinished ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'
                    }`}>
                      {session.isFinished ? 'Concluída' : 'Em Aberto'}
                    </span>
                  </div>

                  <h4 className="text-xl font-black text-slate-800 mb-1">{session.sector}</h4>
                  <p className="text-sm text-slate-400 font-bold mb-4 uppercase tracking-tighter">{session.id} • {session.createdAt}</p>

                  <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                    <span className="text-xs font-bold text-slate-500">{session.entries.length} itens conferidos</span>
                    <div className="flex items-center gap-1 text-blue-600 text-xs font-black uppercase tracking-widest">
                      Gerenciar <ChevronRight className="w-4 h-4" />
                    </div>
                  </div>
                </div>
              ))}

              {auditSessions.length === 0 && (
