                      </button>
                   </div>
                </div>
             </div>
          </div>
        </div>
      )}

      {/* MODAL PADRÃO DE NOVO ATIVO (MANTIDO) */}
      {showForm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-in zoom-in-95 duration-300">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl">
                  <Plus className="w-6 h-6" />
                </div>
                <div>
                   <h3 className="text-2xl font-black text-slate-800 tracking-tight">Onboarding de Ativo</h3>
                   <p className="text-slate-500 text-sm font-medium">Cadastre um novo dispositivo individualmente.</p>
                </div>
              </div>
              <button onClick={() => setShowForm(false)} className="p-3 hover:bg-slate-200 rounded-full transition-colors">
                <X className="w-6 h-6 text-slate-500" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 overflow-y-auto space-y-8">
               <div className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2 col-span-full">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Empresa Unidade</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold" value={newAsset.companyId} onChange={(e) => setNewAsset({...newAsset, companyId: e.target.value})} required>
                        {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo</label>
                      <select className="w-full p-4 rounded-2xl border border-slate-200 bg-white font-bold" value={newAsset.type} onChange={(e) => setNewAsset({...newAsset, type: e.target.value as AssetType})} required>
                        {ASSET_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Marca</label>
                      <input className="w-full p-4 rounded-2xl border border-slate-200 font-bold" value={newAsset.brand || ''} onChange={(e) => setNewAsset({...newAsset, brand: e.target.value})} required />
                    </div>
                  </div>
                  <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 uppercase tracking-widest transition-all active:scale-95">Finalizar Cadastro</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AssetManager;

import React, { useState } from 'react';
import { Package, LogIn, Lock, User as UserIcon, AlertCircle } from 'lucide-react';
import { UserAccount } from '../types';

interface AuthProps {
  onLogin: (user: UserAccount) => void;
  users: UserAccount[];
}

const Auth: React.FC<AuthProps> = ({ onLogin, users }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const inputUser = username.toLowerCase();

    // Procura o usuário na lista (considerando password 'admin' como padrão se não definido)
    const foundUser = users.find(u => 
      u.username.toLowerCase() === inputUser && 
      (u.password === password || (password === 'admin' && !u.password))
    );

    if (foundUser) {
      onLogin(foundUser);
    } else {
      setError('Credenciais inválidas. Verifique seu usuário e senha.');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Logo Section */}
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl shadow-blue-200 mb-4 transform -rotate-6">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">AssetTrack <span className="text-blue-600">Pro</span></h1>
          <p className="text-slate-500 font-medium">Gestão de Ativos de TI Inteligente</p>
        </div>

        {/* Auth Card */}
        <div className="bg-white rounded-[2.5rem] shadow-xl border border-slate-100 p-8 md:p-10 transition-all">
          <div className="flex items-center justify-center mb-8">
            <div className="flex items-center gap-2 text-blue-600">
               <LogIn className="w-5 h-5" />
               <span className="text-xl font-black uppercase tracking-widest">Acesso Restrito</span>
            </div>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in fade-in slide-in-from-top-2">
              <AlertCircle className="w-5 h-5" />
              <p className="text-xs font-bold">{error}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-5">
            <div className="space-y-1.5">
              <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                <UserIcon className="w-4 h-4 text-slate-400" /> Usuário
              </label>
              <input 
                type="text"
                required
                autoComplete="username"
                className="w-full p-3.5 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
                placeholder="Usuário"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                <Lock className="w-4 h-4 text-slate-400" /> Senha
              </label>
              <input 
                type="password"
                required
                autoComplete="current-password"
                className="w-full p-3.5 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none transition-all shadow-sm"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
            </div>

            <button 
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-blue-100 transition-all transform active:scale-[0.98] mt-4"
            >
              Acessar Sistema
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect, useRef } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import Auth from './components/Auth';
import { MOCK_ASSETS, MOCK_EMPLOYEES, MOCK_USERS, MOCK_COMPANIES } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, AppModule, AuditSession, Company } from './types';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');

  const [companies, setCompanies] = useState<Company[]>(MOCK_COMPANIES);
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [users, setUsers] = useState<UserAccount[]>(MOCK_USERS);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  const [requests, setRequests] = useState<EquipmentRequest[]>([
    {
      id: 'REQ-1',
      requesterId: '2',
      employeeId: '1',
      items: ['Notebook', 'Mouse', 'Monitor'],
      itemFulfillments: [
        { type: 'Notebook', isPurchaseOrder: true, purchaseStatus: 'Pendente' },
        { type: 'Mouse', isPurchaseOrder: false },
        { type: 'Monitor', isPurchaseOrder: false }
      ],
      status: 'Pendente',
      createdAt: '2024-03-20',
      observation: 'Colaborador novo iniciando na próxima segunda-feira. Necessita de setup completo.'
    }
  ]);

  useEffect(() => {
    if (currentUser && !currentUser.modules.includes(activeTab as AppModule)) {
      if (currentUser.modules.length > 0) {
        setActiveTab(currentUser.modules[0]);
      }
    }
  }, [currentUser, activeTab]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddCompany = (compData: Omit<Company, 'id' | 'createdAt'>) => {
    const newCompany: Company = {
      ...compData,
      id: `COMP-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR')
    };
    setCompanies([...companies, newCompany]);
  };

  const handleUpdateCompany = (updatedCompany: Company) => {
    setCompanies(companies.map(c => c.id === updatedCompany.id ? updatedCompany : c));
  };

  const handleAddAsset = (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      id: `AST-${Math.floor(Math.random() * 10000)}`,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${Math.random().toString(36).substr(2, 9)}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleAssetCreatedFromPurchase = (assetData: Omit<Asset, 'createdAt' | 'qrCode'>) => {
    const newAsset: Asset = {
      ...assetData,
      createdAt: new Date().toLocaleDateString('pt-BR'),
      qrCode: `QR-${assetData.id}`,
    };
    setAssets([newAsset, ...assets]);
  };

  const handleUpdateAsset = (updatedAsset: Asset) => {
    setAssets(assets.map(a => a.id === updatedAsset.id ? updatedAsset : a));
  };

  const handleAddEmployee = (empData: Omit<Employee, 'id'>) => {
    const newEmp: Employee = { ...empData, id: String(employees.length + 1) };
    setEmployees([newEmp, ...employees]);
  };

  const handleAddRequest = (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const newReq: EquipmentRequest = {
      ...reqData,
      id: `REQ-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
      status: 'Pendente',
      createdAt: new Date().toLocaleDateString('pt-BR'),
      itemFulfillments: reqData.items.map(type => ({ type, isPurchaseOrder: false }))
    };
    setRequests([newReq, ...requests]);
  };

  const handleUpdateStatus = (id: string, status: EquipmentRequest['status']) => {
    setRequests(requests.map(r => r.id === id ? { ...r, status } : r));
  };

  const handleUpdateRequest = (updatedReq: EquipmentRequest) => {
    setRequests(requests.map(r => r.id === updatedReq.id ? updatedReq : r));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return (
          <CompanyManager 
            companies={companies} 
            assets={assets}
            onAddCompany={handleAddCompany}
            onUpdateCompany={handleUpdateCompany}
            onRemoveCompany={(id) => setCompanies(companies.filter(c => c.id !== id))}
          />
        );
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            companies={companies}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={(id) => setAssets(assets.filter(a => a.id !== id))} 
          />
        );
      case 'maintenance':
        return (
          <MaintenanceManager 
            assets={assets}
            employees={employees}
            companies={companies}
            onUpdateAsset={handleUpdateAsset}
          />
        );
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      case 'requests':
        return (
          <RequestsManager 
            requests={requests} 
            employees={employees} 
            assets={assets}
            onAddRequest={handleAddRequest} 
            onUpdateStatus={handleUpdateStatus}
            onUpdateRequest={handleUpdateRequest}
          />
        );
      case 'purchase-orders':
        return (
          <PurchaseOrderManager 
            requests={requests} 
            employees={employees}
            onUpdateRequest={handleUpdateRequest}
            onAssetCreated={handleAssetCreatedFromPurchase}
          />
        );
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'user-management':
        return (
          <UserManager 
            users={users} 
            onAddUser={(u) => setUsers([...users, {...u, id: String(Date.now())}])}
            onUpdateUser={(u) => setUsers(users.map(old => old.id === u.id ? u : old))}
            onRemoveUser={(id) => setUsers(users.filter(u => u.id !== id))}
          />
        );
      case 'inventory-check':
        return (
          <InventoryCheckManager 
            assets={assets}
            employees={employees}
            auditSessions={auditSessions}
            onAddAuditSession={(s) => setAuditSessions([...auditSessions, s])}
            onUpdateAuditSession={(s) => setAuditSessions(auditSessions.map(old => old.id === s.id ? s : old))}
            onGenerateDivergenceRequest={() => {}} 
          />
        );
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo em Desenvolvimento</div>;
    }
  };

  if (!isAuthenticated || !currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser}
      onLogout={handleLogout}
      requests={requests}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Building2, Plus, Search, Trash2, Edit2, Package, Calendar, ShieldCheck, X } from 'lucide-react';
import { Company, Asset } from '../types';

interface CompanyManagerProps {
  companies: Company[];
  assets: Asset[];
  onAddCompany: (company: Omit<Company, 'id' | 'createdAt'>) => void;
  onUpdateCompany: (company: Company) => void;
  onRemoveCompany: (id: string) => void;
}

const CompanyManager: React.FC<CompanyManagerProps> = ({ companies, assets, onAddCompany, onUpdateCompany, onRemoveCompany }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingCompany, setEditingCompany] = useState<Company | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({ name: '', cnpj: '' });

  const filteredCompanies = companies.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.cnpj?.includes(searchTerm)
  );

  const getAssetCount = (companyId: string) => assets.filter(a => a.companyId === companyId).length;

  const handleEdit = (company: Company) => {
    setEditingCompany(company);
    setFormData({ name: company.name, cnpj: company.cnpj || '' });
    setShowForm(true);
  };

  const handleOpenCreate = () => {
    setEditingCompany(null);
    setFormData({ name: '', cnpj: '' });
    setShowForm(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCompany) {
      onUpdateCompany({
        ...editingCompany,
        name: formData.name,
        cnpj: formData.cnpj
      });
    } else {
      onAddCompany(formData);
    }
    setFormData({ name: '', cnpj: '' });
    setShowForm(false);
    setEditingCompany(null);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="relative flex-1 max-w-md w-full">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input 
            type="text" 
            placeholder="Buscar empresa ou CNPJ..." 
            className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 bg-white focus:ring-2 focus:ring-blue-500 outline-none shadow-sm font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button 
          onClick={handleOpenCreate}
          className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-blue-100 flex items-center gap-2 transition-all transform active:scale-95"
        >
          <Plus className="w-5 h-5" />
          Cadastrar Empresa
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredCompanies.map(company => (
          <div key={company.id} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">
            <div className="flex justify-between items-start mb-6">
              <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-all duration-500">
                <Building2 className="w-7 h-7" />
              </div>
              <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button 
                  onClick={() => handleEdit(company)}
                  className="p-2 text-slate-400 hover:text-blue-600 transition-colors"
                >
                  <Edit2 className="w-4 h-4" />
                </button>
                <button 
                  onClick={() => onRemoveCompany(company.id)}
                  className="p-2 text-slate-400 hover:text-rose-600 transition-colors"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>

            <div className="space-y-1">
              <h4 className="text-xl font-black text-slate-800 tracking-tight">{company.name}</h4>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{company.cnpj || 'CNPJ não informado'}</p>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-50 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Package className="w-4 h-4 text-slate-300" />
                <span className="text-sm font-black text-slate-700">{getAssetCount(company.id)} Ativos</span>
              </div>
              <div className="flex items-center gap-2 text-slate-400">
                <Calendar className="w-3.5 h-3.5" />
                <span className="text-[10px] font-bold uppercase tracking-tighter">Desde {company.createdAt}</span>
              </div>
            </div>

            <div className="absolute top-[-20%] right-[-10%] w-32 h-32 bg-blue-500/5 rounded-full blur-3xl pointer-events-none" />
          </div>
        ))}

        {filteredCompanies.length === 0 && (
          <div className="col-span-full py-20 text-center flex flex-col items-center justify-center bg-white rounded-[3rem] border border-dashed border-slate-200">
             <Building2 className="w-12 h-12 text-slate-200 mb-4" />
             <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Nenhuma empresa encontrada</p>
          </div>
        )}
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-lg rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className={`p-8 ${editingCompany ? 'bg-amber-600' : 'bg-blue-600'} text-white flex justify-between items-center transition-colors`}>
               <div className="flex items-center gap-3">
                  {editingCompany ? <Edit2 className="w-6 h-6" /> : <Building2 className="w-6 h-6" />}
                  <h3 className="text-2xl font-black tracking-tight">
                    {editingCompany ? 'Editar Empresa' : 'Nova Empresa'}
                  </h3>
               </div>
               <button onClick={() => setShowForm(false)} className="p-2 hover:bg-white/10 rounded-full">
                  <X className="w-6 h-6" />
               </button>
            </div>

            <form onSubmit={handleSubmit} className="p-10 space-y-6">
