import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import PrintManager from './components/PrintManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, AppModule, AuditSession, Company } from './types';
import { db } from './services/supabase';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);

  const [companies, setCompanies] = useState<Company[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [users, setUsers] = useState<UserAccount[]>(MOCK_USERS);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);

  // Carregamento inicial de dados do Banco de Dados
  useEffect(() => {
    const loadInitialData = async () => {
      try {
        setIsLoading(true);
        const [fetchedAssets, fetchedCompanies] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch()
        ]);
        setAssets(fetchedAssets);
        setCompanies(fetchedCompanies);
      } catch (err) {
        console.error("Erro ao carregar dados do banco:", err);
      } finally {
        setIsLoading(false);
      }
    };

    if (isAuthenticated) {
      loadInitialData();
    }
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddCompany = async (compData: Omit<Company, 'id' | 'createdAt'>) => {
    const id = `COMP-${Math.floor(Math.random() * 10000)}`;
    const newCompany = { ...compData, id };

    try {
      const saved = await db.companies.insert(newCompany);
      setCompanies([...companies, saved]);
    } catch (err) {
      alert("Erro ao salvar empresa no banco de dados.");
    }
  };

  const handleAddAsset = async (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const id = `AST-${Math.floor(Math.random() * 10000)}`;
    const newAsset = {
      ...assetData,
      id,
      qr_code: `QR-${id}`,
    };

    try {
      const saved = await db.assets.insert(newAsset);
      setAssets([saved, ...assets]);
    } catch (err) {
      alert("Erro ao salvar ativo no banco de dados.");
    }
  };

  const handleUpdateAsset = async (updatedAsset: Asset) => {
    try {
      const saved = await db.assets.update(updatedAsset.id, updatedAsset);
      setAssets(assets.map(a => a.id === updatedAsset.id ? saved : a));
    } catch (err) {
      alert("Erro ao atualizar ativo.");
    }
  };

  const handleRemoveAsset = async (id: string) => {
    if(!confirm("Deseja realmente excluir este ativo?")) return;
    try {
      await db.assets.delete(id);
      setAssets(assets.filter(a => a.id !== id));
    } catch (err) {
      alert("Erro ao excluir ativo.");
    }
  };

  const renderContent = () => {
    if (isLoading) return <div className="p-20 text-center font-black animate-pulse text-blue-600">Sincronizando Banco de Dados...</div>;

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return (
          <CompanyManager 
            companies={companies} 
            assets={assets}
            onAddCompany={handleAddCompany}
            onUpdateCompany={() => {}} // TODO: Implementar update no db service
            onRemoveCompany={() => {}} // TODO: Implementar delete no db service
          />
        );
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            companies={companies}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={handleRemoveAsset} 
          />
        );
      case 'maintenance':
        return <MaintenanceManager assets={assets} employees={employees} companies={companies} onUpdateAsset={handleUpdateAsset} />;
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo em Nuvem</div>;
    }
  };

  if (!isAuthenticated || !currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser}
      onLogout={handleLogout}
      requests={requests}
    >
      {renderContent()}
    </Layout>
  );
};

