import { createClient } from '@supabase/supabase-js';
import { Asset, Company, Employee } from '../types';

// O host fornecido pelo usuário indica o ID do projeto: hauaemihkmrpjmzgpigh
const supabaseUrl = process.env.SUPABASE_URL || 'https://hauaemihkmrpjmzgpigh.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Mapeadores para converter snake_case (DB) para camelCase (App)
const mapAsset = (data: any): Asset => ({
  id: data.id,
  companyId: data.company_id,
  type: data.type,
  brand: data.brand,
  model: data.model,
  ram: data.ram,
  storage: data.storage,
  processor: data.processor,
  screenSize: data.screen_size,
  observations: data.observations,
  photos: data.photos || [],
  status: data.status,
  assignedTo: data.assigned_to,
  qrCode: data.qr_code,
  createdAt: data.created_at
});

const mapAssetToDB = (asset: any) => ({
  id: asset.id,
  company_id: asset.companyId,
  type: asset.type,
  brand: asset.brand,
  model: asset.model,
  ram: asset.ram,
  storage: asset.storage,
  processor: asset.processor,
  screen_size: asset.screenSize,
  observations: asset.observations,
  photos: asset.photos,
  status: asset.status,
  assigned_to: asset.assignedTo,
  qr_code: asset.qrCode
});

export const db = {
  assets: {
    fetch: async (): Promise<Asset[]> => {
      const { data, error } = await supabase.from('assets').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []).map(mapAsset);
    },
    insert: async (asset: Omit<Asset, 'createdAt'>): Promise<Asset> => {
      const dbItem = mapAssetToDB(asset);
      const { data, error } = await supabase.from('assets').insert([dbItem]).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    update: async (id: string, updates: Partial<Asset>): Promise<Asset> => {
      const dbUpdates = mapAssetToDB(updates);
      // Remove campos indefinidos para não sobrescrever com null indesejado
      Object.keys(dbUpdates).forEach(key => (dbUpdates as any)[key] === undefined && delete (dbUpdates as any)[key]);

      const { data, error } = await supabase.from('assets').update(dbUpdates).eq('id', id).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    delete: async (id: string) => {
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  companies: {
    fetch: async (): Promise<Company[]> => {
      const { data, error } = await supabase.from('companies').select('*').order('name');
      if (error) throw error;
      return data.map(c => ({ ...c, createdAt: c.created_at }));
    },
    insert: async (company: Omit<Company, 'createdAt'>): Promise<Company> => {
      const { data, error } = await supabase.from('companies').insert([company]).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    },
    update: async (company: Company): Promise<Company> => {
      const { data, error } = await supabase.from('companies').update({ name: company.name, cnpj: company.cnpj }).eq('id', company.id).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    },
    delete: async (id: string) => {
      const { error } = await supabase.from('companies').delete().eq('id', id);
      if (error) throw error;
    }
  },
  employees: {
    fetch: async (): Promise<Employee[]> => {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (error) throw error;
      return data.map(e => ({
        id: e.id,
        companyId: e.company_id,
        name: e.name,
        sector: e.sector,
        role: e.role,
        cpf: e.cpf
      }));
    },
    insert: async (emp: Omit<Employee, 'id'>): Promise<Employee> => {
      const id = `EMP-${Math.floor(Math.random() * 10000)}`;
      const dbItem = { id, company_id: emp.companyId, name: emp.name, sector: emp.sector, role: emp.role, cpf: emp.cpf };
      const { data, error } = await supabase.from('employees').insert([dbItem]).select();
      if (error) throw error;
      return { ...emp, id: data[0].id };
    }
  }
};

