  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);

  // Sincronização em Tempo Real com Supabase
  useEffect(() => {
    const loadData = async () => {
      if (!isAuthenticated) return;

      try {
        setIsLoading(true);
        const [a, c, e] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch(),
          db.employees.fetch()
        ]);
        setAssets(a);
        setCompanies(c);
        setEmployees(e);
      } catch (err) {
        console.error("Falha ao sincronizar com banco de dados:", err);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  // HANDLERS DE EMPRESA
  const handleAddCompany = async (compData: Omit<Company, 'id' | 'createdAt'>) => {
    const id = `COMP-${Math.floor(Math.random() * 10000)}`;
    try {
      const saved = await db.companies.insert({ ...compData, id });
      setCompanies([...companies, saved]);
    } catch (err) {
      alert("Erro ao salvar empresa.");
    }
  };

  const handleUpdateCompany = async (updated: Company) => {
    try {
      const saved = await db.companies.update(updated);
      setCompanies(companies.map(c => c.id === updated.id ? saved : c));
    } catch (err) {
      alert("Erro ao atualizar empresa.");
    }
  };

  const handleRemoveCompany = async (id: string) => {
    try {
      await db.companies.delete(id);
      setCompanies(companies.filter(c => c.id !== id));
    } catch (err) {
      alert("Erro ao remover empresa (verifique se há ativos vinculados).");
    }
  };

  // HANDLERS DE ATIVOS
  const handleAddAsset = async (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 10000)}`;
    const newAsset: Omit<Asset, 'createdAt'> = {
      ...assetData,
      id,
      qrCode: `QR-${id}`,
      photos: assetData.photos || []
    };

    try {
      const saved = await db.assets.insert(newAsset);
      setAssets([saved, ...assets]);
    } catch (err) {
      alert("Erro ao salvar ativo.");
    }
  };

  const handleUpdateAsset = async (updatedAsset: Asset) => {
    try {
      const saved = await db.assets.update(updatedAsset.id, updatedAsset);
      setAssets(assets.map(a => a.id === updatedAsset.id ? saved : a));
    } catch (err) {
      alert("Erro ao atualizar ativo.");
    }
  };

  const handleRemoveAsset = async (id: string) => {
    try {
      await db.assets.delete(id);
      setAssets(assets.filter(a => a.id !== id));
    } catch (err) {
      alert("Erro ao remover ativo.");
    }
  };

  // HANDLERS DE COLABORADORES
  const handleAddEmployee = async (empData: Omit<Employee, 'id'>) => {
    try {
      const saved = await db.employees.insert(empData);
      setEmployees([...employees, saved]);
    } catch (err) {
      alert("Erro ao cadastrar colaborador.");
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center p-20 space-y-4">
           <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
           <p className="text-blue-600 font-black uppercase tracking-widest text-xs animate-pulse">Sincronizando com a Nuvem...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return (
          <CompanyManager 
            companies={companies} 
            assets={assets}
            onAddCompany={handleAddCompany}
            onUpdateCompany={handleUpdateCompany}
            onRemoveCompany={handleRemoveCompany}
          />
        );
      case 'assets':
        return (
          <AssetManager 
            assets={assets} 
            employees={employees}
            companies={companies}
            onAdd={handleAddAsset} 
            onUpdate={handleUpdateAsset}
            onRemove={handleRemoveAsset} 
          />
        );
      case 'maintenance':
        return <MaintenanceManager assets={assets} employees={employees} companies={companies} onUpdateAsset={handleUpdateAsset} />;
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={handleAddEmployee} />;
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo em Desenvolvimento</div>;
    }
  };

  if (!isAuthenticated || !currentUser) {
    return <Auth onLogin={handleLogin} users={MOCK_USERS} />;
  }

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      currentUser={currentUser}
      onLogout={handleLogout}
      requests={requests}
    >
      {renderContent()}
    </Layout>
  );
};

