import { createClient } from '@supabase/supabase-js';
import { Asset, Company, Employee, EquipmentRequest, AuditSession } from '../types';

const supabaseUrl = process.env.SUPABASE_URL || 'https://hauaemihkmrpjmzgpigh.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Mapeadores para Ativos
const mapAsset = (data: any): Asset => ({
  id: data.id,
  companyId: data.company_id,
  type: data.type,
  brand: data.brand,
  model: data.model,
  ram: data.ram,
  storage: data.storage,
  processor: data.processor,
  screenSize: data.screen_size,
  observations: data.observations,
  photos: data.photos || [],
  status: data.status,
  assignedTo: data.assigned_to,
  qrCode: data.qr_code,
  createdAt: data.created_at
});

const mapAssetToDB = (asset: any) => ({
  id: asset.id,
  company_id: asset.companyId,
  type: asset.type,
  brand: asset.brand,
  model: asset.model,
  ram: asset.ram,
  storage: asset.storage,
  processor: asset.processor,
  screen_size: asset.screenSize,
  observations: asset.observations,
  photos: asset.photos,
  status: asset.status,
  assigned_to: asset.assignedTo,
  qr_code: asset.qrCode
});

export const db = {
  assets: {
    fetch: async (): Promise<Asset[]> => {
      const { data, error } = await supabase.from('assets').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []).map(mapAsset);
    },
    insert: async (asset: Omit<Asset, 'createdAt'>): Promise<Asset> => {
      const { data, error } = await supabase.from('assets').insert([mapAssetToDB(asset)]).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    update: async (id: string, updates: Partial<Asset>): Promise<Asset> => {
      const dbUpdates = mapAssetToDB(updates);
      Object.keys(dbUpdates).forEach(key => (dbUpdates as any)[key] === undefined && delete (dbUpdates as any)[key]);
      const { data, error } = await supabase.from('assets').update(dbUpdates).eq('id', id).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    delete: async (id: string) => {
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  companies: {
    fetch: async (): Promise<Company[]> => {
      const { data, error } = await supabase.from('companies').select('*').order('name');
      if (error) throw error;
      return data.map(c => ({ ...c, createdAt: c.created_at }));
    },
    insert: async (company: Omit<Company, 'createdAt'>): Promise<Company> => {
      const { data, error } = await supabase.from('companies').insert([company]).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    },
    update: async (company: Company): Promise<Company> => {
      const { data, error } = await supabase.from('companies').update({ name: company.name, cnpj: company.cnpj }).eq('id', company.id).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    },
    delete: async (id: string) => {
      const { error } = await supabase.from('companies').delete().eq('id', id);
      if (error) throw error;
    }
  },
  employees: {
    fetch: async (): Promise<Employee[]> => {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (error) throw error;
      return data.map(e => ({
        id: e.id,
        companyId: e.company_id,
        name: e.name,
        sector: e.sector,
        role: e.role,
        cpf: e.cpf
      }));
    },
    insert: async (emp: Omit<Employee, 'id'>): Promise<Employee> => {
      const id = `EMP-${Math.floor(Math.random() * 10000)}`;
      const dbItem = { id, company_id: emp.companyId, name: emp.name, sector: emp.sector, role: emp.role, cpf: emp.cpf };
      const { data, error } = await supabase.from('employees').insert([dbItem]).select();
      if (error) throw error;
      return { ...emp, id: data[0].id };
    }
  },
  requests: {
    fetch: async (): Promise<EquipmentRequest[]> => {
      const { data, error } = await supabase.from('equipment_requests').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return data.map(r => ({
        id: r.id,
        requesterId: r.requester_id,
        employeeId: r.employee_id,
        items: r.items,
        itemFulfillments: r.item_fulfillments,
        observation: r.observation,
        status: r.status,
        type: r.type,
        createdAt: r.created_at
      }));
    },
    insert: async (req: Omit<EquipmentRequest, 'createdAt'>): Promise<EquipmentRequest> => {
      const dbItem = {
        id: req.id,
        requester_id: req.requesterId,
        employee_id: req.employeeId,
        items: req.items,
        item_fulfillments: req.itemFulfillments || [],
        observation: req.observation,
        status: req.status,
        type: req.type
      };
      const { data, error } = await supabase.from('equipment_requests').insert([dbItem]).select();
      if (error) throw error;
      return { ...req, createdAt: data[0].created_at };
    },
    update: async (req: EquipmentRequest): Promise<EquipmentRequest> => {
      const { data, error } = await supabase.from('equipment_requests').update({
        status: req.status,
        item_fulfillments: req.itemFulfillments
      }).eq('id', req.id).select();
      if (error) throw error;
      return { ...req, createdAt: data[0].created_at };
    }
  },
  auditSessions: {
    fetch: async (): Promise<AuditSession[]> => {
      const { data, error } = await supabase.from('audit_sessions').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return data.map(s => ({
        id: s.id,
        sector: s.sector,
        entries: s.entries,
        isFinished: s.is_finished,
        generatedRequestId: s.generated_request_id,
        createdAt: s.created_at
      }));
    },
    insert: async (session: AuditSession): Promise<AuditSession> => {
      const dbItem = {
        id: session.id,
        sector: session.sector,
        entries: session.entries,
        is_finished: session.isFinished,
        generated_request_id: session.generatedRequestId
      };
      const { data, error } = await supabase.from('audit_sessions').insert([dbItem]).select();
      if (error) throw error;
      return { ...session, createdAt: data[0].created_at };
    },
    update: async (session: AuditSession): Promise<AuditSession> => {
      const { data, error } = await supabase.from('audit_sessions').update({
        entries: session.entries,
        is_finished: session.isFinished,
        generated_request_id: session.generatedRequestId
      }).eq('id', session.id).select();
      if (error) throw error;
      return { ...session, createdAt: data[0].created_at };
    }
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Company, AuditSession } from './types';
import { db } from './services/supabase';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(true);

  const [companies, setCompanies] = useState<Company[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  // Sincronização Global com Supabase
  useEffect(() => {
    const loadData = async () => {
      if (!isAuthenticated) return;

      try {
        setIsLoading(true);
        const [a, c, e, r, s] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch(),
          db.employees.fetch(),
          db.requests.fetch(),
          db.auditSessions.fetch()
        ]);
        setAssets(a);
        setCompanies(c);
        setEmployees(e);
        setRequests(r);
        setAuditSessions(s);
      } catch (err) {
        console.error("Falha ao sincronizar com banco de dados:", err);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  // HANDLERS PERSISTENTES
  const handleAddAsset = async (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'>) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const newAsset = { ...assetData, id, qrCode: `QR-${id}` };
    try {
      const saved = await db.assets.insert(newAsset);
      setAssets([saved, ...assets]);
    } catch (err) { alert("Erro ao salvar ativo."); }
  };

  const handleUpdateAsset = async (updated: Asset) => {
    try {
      const saved = await db.assets.update(updated.id, updated);
      setAssets(assets.map(a => a.id === updated.id ? saved : a));
    } catch (err) { alert("Erro ao atualizar ativo."); }
  };

  const handleAddRequest = async (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: Omit<EquipmentRequest, 'createdAt'> = {
      ...reqData,
      id,
      status: 'Pendente',
      itemFulfillments: reqData.items.map(type => ({ type, isPurchaseOrder: false }))
    };
    try {
      const saved = await db.requests.insert(newReq);
      setRequests([saved, ...requests]);
    } catch (err) { alert("Erro ao criar requisição."); }
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    try {
      const saved = await db.requests.update(req);
      setRequests(requests.map(r => r.id === req.id ? saved : r));
    } catch (err) { alert("Erro ao atualizar requisição."); }
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    try {
      const saved = await db.auditSessions.update(session);
      setAuditSessions(auditSessions.map(s => s.id === session.id ? saved : s));
    } catch (err) { alert("Erro ao atualizar auditoria."); }
  };

  const handleAddAuditSession = async (session: AuditSession) => {
    try {
      const saved = await db.auditSessions.insert(session);
      setAuditSessions([saved, ...auditSessions]);
    } catch (err) { alert("Erro ao criar auditoria."); }
  };

  const renderContent = () => {
    if (isLoading) return (
      <div className="flex flex-col items-center justify-center p-20 space-y-4">
         <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
         <p className="text-blue-600 font-black uppercase tracking-widest text-xs animate-pulse">Sincronizando Banco PostgreSQL...</p>
      </div>
    );

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return <CompanyManager companies={companies} assets={assets} onAddCompany={async (c) => { const s = await db.companies.insert(c); setCompanies([...companies, s]); }} onUpdateCompany={async (c) => { const s = await db.companies.update(c); setCompanies(companies.map(i => i.id === c.id ? s : i)); }} onRemoveCompany={async (id) => { await db.companies.delete(id); setCompanies(companies.filter(c => c.id !== id)); }} />;
      case 'assets':
        return <AssetManager assets={assets} employees={employees} companies={companies} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={async (id) => { await db.assets.delete(id); setAssets(assets.filter(a => a.id !== id)); }} />;
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={async (e) => { const s = await db.employees.insert(e); setEmployees([...employees, s]); }} />;
      case 'requests':
        return <RequestsManager requests={requests} employees={employees} assets={assets} onAddRequest={handleAddRequest} onUpdateRequest={handleUpdateRequest} onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if (req) handleUpdateRequest({...req, status}); }} />;
      case 'maintenance':
        return <MaintenanceManager assets={assets} employees={employees} companies={companies} onUpdateAsset={handleUpdateAsset} />;
      case 'purchase-orders':
        return <PurchaseOrderManager requests={requests} employees={employees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} />;
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'inventory-check':
        return <InventoryCheckManager assets={assets} employees={employees} auditSessions={auditSessions} onAddAuditSession={handleAddAuditSession} onUpdateAuditSession={handleUpdateAuditSession} onGenerateDivergenceRequest={(sector, assetIds) => handleAddRequest({ requesterId: currentUser?.id || '1', employeeId: employees.find(e => e.sector === sector)?.id || '', items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), observation: `Divergência de auditoria no setor ${sector}`, type: 'Divergencia' })} />;
      case 'user-management':
        return <UserManager users={MOCK_USERS} onAddUser={()=>{}} onUpdateUser={()=>{}} onRemoveUser={()=>{}} />;
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo Cloud</div>;
    }
  };

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={MOCK_USERS} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {renderContent()}
    </Layout>
  );
};

