import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Company, AuditSession } from './types';
import { db, isSupabaseConfigured } from './services/supabase';
import { AlertTriangle } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(false); // Inicia como false para mostrar Auth
  const [dbError, setDbError] = useState<string | null>(null);

  const [companies, setCompanies] = useState<Company[]>([]);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  // Sincronização Global com Supabase
  useEffect(() => {
    const loadData = async () => {
      if (!isAuthenticated || !isSupabaseConfigured) return;

      try {
        setIsLoading(true);
        setDbError(null);
        const [a, c, e, r, s] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch(),
          db.employees.fetch(),
          db.requests.fetch(),
          db.auditSessions.fetch()
        ]);
        setAssets(a);
        setCompanies(c);
        setEmployees(e);
        setRequests(r);
        setAuditSessions(s);
      } catch (err: any) {
        console.error("Falha ao sincronizar com banco de dados:", err);
        setDbError(err.message || "Erro desconhecido ao conectar com o Supabase.");
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: Omit<Asset, 'id' | 'createdAt' | 'qrCode'> & { id?: string }) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const newAsset = { ...assetData, id, qrCode: `QR-${id}` };
    try {
      const saved = await db.assets.insert(newAsset as any);
      setAssets([saved, ...assets]);
    } catch (err) { alert("Erro ao salvar ativo no banco."); }
  };

  const handleUpdateAsset = async (updated: Asset) => {
    try {
      const saved = await db.assets.update(updated.id, updated);
      setAssets(assets.map(a => a.id === updated.id ? saved : a));
    } catch (err) { alert("Erro ao atualizar ativo."); }
  };

  const handleAddRequest = async (reqData: Omit<EquipmentRequest, 'id' | 'createdAt' | 'status'>) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq: Omit<EquipmentRequest, 'createdAt'> = {
      ...reqData,
      id,
      status: 'Pendente',
      itemFulfillments: reqData.items.map(type => ({ type, isPurchaseOrder: false }))
    };
    try {
      const saved = await db.requests.insert(newReq);
      setRequests([saved, ...requests]);
    } catch (err) { alert("Erro ao criar requisição."); }
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    try {
      const saved = await db.requests.update(req);
      setRequests(requests.map(r => r.id === req.id ? saved : r));
    } catch (err) { alert("Erro ao atualizar requisição."); }
  };

  const handleUpdateAuditSession = async (session: AuditSession) => {
    try {
      const saved = await db.auditSessions.update(session);
      setAuditSessions(auditSessions.map(s => s.id === session.id ? saved : s));
    } catch (err) { alert("Erro ao atualizar auditoria."); }
  };

  const handleAddAuditSession = async (session: AuditSession) => {
    try {
      const saved = await db.auditSessions.insert(session);
      setAuditSessions([saved, ...auditSessions]);
    } catch (err) { alert("Erro ao criar auditoria."); }
  };

  const renderContent = () => {
    if (dbError) {
      return (
        <div className="flex flex-col items-center justify-center p-20 text-center space-y-6 bg-rose-50 rounded-[3rem] border-2 border-rose-100">
           <AlertTriangle className="w-16 h-16 text-rose-500 animate-pulse" />
           <div>
              <h2 className="text-2xl font-black text-rose-700">Erro de Conexão Cloud</h2>
              <p className="text-rose-600 max-w-md mx-auto mt-2 font-medium">{dbError}</p>
              <p className="text-slate-400 text-xs mt-4 uppercase font-black">Certifique-se de que a tabela do banco existe no Supabase</p>
           </div>
           <button onClick={() => window.location.reload()} className="bg-rose-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg shadow-rose-200">Tentar Novamente</button>
        </div>
      );
    }

    if (isLoading) return (
      <div className="flex flex-col items-center justify-center p-20 space-y-4">
         <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
         <p className="text-blue-600 font-black uppercase tracking-widest text-xs animate-pulse">Sincronizando Banco PostgreSQL...</p>
      </div>
    );

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies':
        return <CompanyManager companies={companies} assets={assets} onAddCompany={async (c) => { const s = await db.companies.insert(c); setCompanies([...companies, s]); }} onUpdateCompany={async (c) => { const s = await db.companies.update(c); setCompanies(companies.map(i => i.id === c.id ? s : i)); }} onRemoveCompany={async (id) => { await db.companies.delete(id); setCompanies(companies.filter(c => c.id !== id)); }} />;
      case 'assets':
        return <AssetManager assets={assets} employees={employees} companies={companies} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={async (id) => { await db.assets.delete(id); setAssets(assets.filter(a => a.id !== id)); }} />;
      case 'employees':
        return <EmployeeManager employees={employees} onAdd={async (e) => { const s = await db.employees.insert(e); setEmployees([...employees, s]); }} />;
      case 'requests':
        return <RequestsManager requests={requests} employees={employees} assets={assets} onAddRequest={handleAddRequest} onUpdateRequest={handleUpdateRequest} onUpdateStatus={async (id, status) => { const req = requests.find(r => r.id === id); if (req) handleUpdateRequest({...req, status}); }} />;
      case 'maintenance':
        return <MaintenanceManager assets={assets} employees={employees} companies={companies} onUpdateAsset={handleUpdateAsset} />;
      case 'purchase-orders':
        return <PurchaseOrderManager requests={requests} employees={employees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} />;
      case 'printing':
        return <PrintManager assets={assets} />;
      case 'inventory-check':
        return <InventoryCheckManager assets={assets} employees={employees} auditSessions={auditSessions} onAddAuditSession={handleAddAuditSession} onUpdateAuditSession={handleUpdateAuditSession} onGenerateDivergenceRequest={(sector, assetIds) => handleAddRequest({ requesterId: currentUser?.id || '1', employeeId: employees.find(e => e.sector === sector)?.id || '', items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), observation: `Divergência de auditoria no setor ${sector}`, type: 'Divergencia' })} />;
      case 'user-management':
        return <UserManager users={MOCK_USERS} onAddUser={()=>{}} onUpdateUser={()=>{}} onRemoveUser={()=>{}} />;
      default:
        return <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest">Módulo Cloud</div>;
    }
  };

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={MOCK_USERS} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      {renderContent()}
    </Layout>
  );
};

export default App;

