import { createClient } from '@supabase/supabase-js';
import { Asset, Company, Employee, EquipmentRequest, AuditSession } from '../types';

// A URL do seu projeto baseada no ID fornecido
const supabaseUrl = process.env.SUPABASE_URL || 'https://hauaemihkmrpjmzgpigh.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

// O sistema só tentará conectar se a chave Anon for fornecida nas variáveis de ambiente
export const isSupabaseConfigured = supabaseAnonKey.length > 10;

export const supabase = isSupabaseConfigured 
  ? createClient(supabaseUrl, supabaseAnonKey)
  : null;

// Funções de mapeamento para manter consistência entre DB (snake_case) e App (camelCase)
const mapAsset = (data: any): Asset => ({
  id: data.id,
  companyId: data.company_id,
  type: data.type,
  brand: data.brand,
  model: data.model,
  ram: data.ram,
  storage: data.storage,
  processor: data.processor,
  screenSize: data.screen_size,
  observations: data.observations,
  photos: data.photos || [],
  status: data.status,
  assignedTo: data.assigned_to,
  qrCode: data.qr_code,
  createdAt: data.created_at
});

const mapAssetToDB = (asset: any) => ({
  id: asset.id,
  company_id: asset.companyId,
  type: asset.type,
  brand: asset.brand,
  model: asset.model,
  ram: asset.ram,
  storage: asset.storage,
  processor: asset.processor,
  screen_size: asset.screenSize,
  observations: asset.observations,
  photos: asset.photos,
  status: asset.status,
  assigned_to: asset.assignedTo,
  qr_code: asset.qrCode
});

export const db = {
  assets: {
    fetch: async (): Promise<Asset[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('assets').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []).map(mapAsset);
    },
    insert: async (asset: Omit<Asset, 'createdAt'>): Promise<Asset> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('assets').insert([mapAssetToDB(asset)]).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    update: async (id: string, updates: Partial<Asset>): Promise<Asset> => {
      if (!supabase) throw new Error("Offline");
      const dbUpdates = mapAssetToDB(updates);
      Object.keys(dbUpdates).forEach(key => (dbUpdates as any)[key] === undefined && delete (dbUpdates as any)[key]);
      const { data, error } = await supabase.from('assets').update(dbUpdates).eq('id', id).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    delete: async (id: string) => {
      if (!supabase) throw new Error("Offline");
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  companies: {
    fetch: async (): Promise<Company[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('companies').select('*').order('name');
      if (error) throw error;
      return data.map(c => ({ ...c, createdAt: c.created_at }));
    },
    insert: async (company: Omit<Company, 'createdAt'>): Promise<Company> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('companies').insert([company]).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    }
  },
  employees: {
    fetch: async (): Promise<Employee[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (error) throw error;
      return data.map(e => ({
        id: e.id,
        companyId: e.company_id,
        name: e.name,
        sector: e.sector,
        role: e.role,
        cpf: e.cpf
      }));
    },
    insert: async (emp: Omit<Employee, 'id'>): Promise<Employee> => {
      if (!supabase) throw new Error("Offline");
      const id = `EMP-${Math.floor(Math.random() * 10000)}`;
      const { data, error } = await supabase.from('employees').insert([{ 
        id, 
        company_id: emp.companyId, 
        name: emp.name, 
        sector: emp.sector, 
        role: emp.role, 
        cpf: emp.cpf 
      }]).select();
      if (error) throw error;
      return { ...emp, id: data[0].id };
    }
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS, MOCK_ASSETS, MOCK_COMPANIES, MOCK_EMPLOYEES } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Company, AuditSession } from './types';
import { db, isSupabaseConfigured } from './services/supabase';
import { Cloud, CloudOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const [companies, setCompanies] = useState<Company[]>(MOCK_COMPANIES);
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  useEffect(() => {
    const loadData = async () => {
      if (!isAuthenticated || !isSupabaseConfigured) return;

      try {
        setIsLoading(true);
        const [a, c, e] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch(),
          db.employees.fetch()
        ]);

        // Se houver dados no banco, substitui os mocks
        if (c.length > 0) setCompanies(c);
        if (a.length > 0) setAssets(a);
        if (e.length > 0) setEmployees(e);
      } catch (err) {
        console.warn("Erro ao carregar dados do Supabase. Usando dados locais.", err);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const newAsset = { ...assetData, id, qrCode: `QR-${id}` };

    if (isSupabaseConfigured) {
      try {
        const saved = await db.assets.insert(newAsset);
        setAssets([saved, ...assets]);
      } catch (e) { alert("Erro ao salvar no banco."); }
    } else {
      setAssets([{ ...newAsset, createdAt: new Date().toISOString() } as Asset, ...assets]);
    }
  };

  const renderContent = () => {
    if (isLoading) return (
      <div className="flex flex-col items-center justify-center p-20">
         <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
         <p className="mt-4 text-blue-600 font-bold uppercase tracking-widest text-xs">Sincronizando Cloud...</p>
      </div>
    );

    switch (activeTab) {
      case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies': return <CompanyManager companies={companies} assets={assets} onAddCompany={async (c) => { if(isSupabaseConfigured) { const s = await db.companies.insert(c); setCompanies([...companies, s]); } else setCompanies([...companies, {...c, id: Math.random().toString(), createdAt: ''}])}} onUpdateCompany={()=>{}} onRemoveCompany={()=>{}} />;
      case 'assets': return <AssetManager assets={assets} employees={employees} companies={companies} onAdd={handleAddAsset} onUpdate={()=>{}} onRemove={()=>{}} />;
      case 'employees': return <EmployeeManager employees={employees} onAdd={async (e) => { if(isSupabaseConfigured) { const s = await db.employees.insert(e); setEmployees([...employees, s]); } else setEmployees([...employees, {...e, id: Math.random().toString()}])}} />;
      default: return <div className="p-20 text-center text-slate-400 font-bold uppercase">Módulo em Desenvolvimento</div>;
    }
  };

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={MOCK_USERS} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      <div className="mb-4 flex items-center gap-2">
        {isSupabaseConfigured ? (
          <div className="flex items-center gap-2 bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-emerald-100">
            <Cloud className="w-3 h-3" /> Cloud Conectado
          </div>
        ) : (
          <div className="flex items-center gap-2 bg-amber-50 text-amber-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
            <CloudOff className="w-3 h-3" /> Modo Offline (Local)
          </div>
        )}
      </div>
      {renderContent()}
    </Layout>
  );
};

export default App;

