import { createClient } from '@supabase/supabase-js';
import { Asset, Company, Employee, EquipmentRequest, AuditSession } from '../types';

// A URL do seu projeto baseada no ID fornecido
const supabaseUrl = process.env.SUPABASE_URL || 'https://hauaemihkmrpjmzgpigh.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

// O sistema só tentará conectar se a chave Anon for fornecida nas variáveis de ambiente
export const isSupabaseConfigured = supabaseAnonKey.length > 10;

export const supabase = isSupabaseConfigured 
  ? createClient(supabaseUrl, supabaseAnonKey)
  : null;

// Mapeadores para consistência App (camelCase) vs DB (snake_case)
const mapAsset = (data: any): Asset => ({
  id: data.id,
  companyId: data.company_id,
  type: data.type,
  brand: data.brand,
  model: data.model,
  ram: data.ram,
  storage: data.storage,
  processor: data.processor,
  screenSize: data.screen_size,
  observations: data.observations,
  photos: data.photos || [],
  status: data.status,
  assignedTo: data.assigned_to,
  qrCode: data.qr_code,
  createdAt: data.created_at
});

const mapAssetToDB = (asset: any) => ({
  id: asset.id,
  company_id: asset.companyId,
  type: asset.type,
  brand: asset.brand,
  model: asset.model,
  ram: asset.ram,
  storage: asset.storage,
  processor: asset.processor,
  screen_size: asset.screenSize,
  observations: asset.observations,
  photos: asset.photos,
  status: asset.status,
  assigned_to: asset.assignedTo,
  qr_code: asset.qrCode
});

export const db = {
  assets: {
    fetch: async (): Promise<Asset[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('assets').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return (data || []).map(mapAsset);
    },
    insert: async (asset: Omit<Asset, 'createdAt'>): Promise<Asset> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('assets').insert([mapAssetToDB(asset)]).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    update: async (id: string, updates: Partial<Asset>): Promise<Asset> => {
      if (!supabase) throw new Error("Offline");
      const dbUpdates = mapAssetToDB(updates);
      Object.keys(dbUpdates).forEach(key => (dbUpdates as any)[key] === undefined && delete (dbUpdates as any)[key]);
      const { data, error } = await supabase.from('assets').update(dbUpdates).eq('id', id).select();
      if (error) throw error;
      return mapAsset(data[0]);
    },
    delete: async (id: string) => {
      if (!supabase) throw new Error("Offline");
      const { error } = await supabase.from('assets').delete().eq('id', id);
      if (error) throw error;
    }
  },
  companies: {
    fetch: async (): Promise<Company[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('companies').select('*').order('name');
      if (error) throw error;
      return data.map(c => ({ ...c, createdAt: c.created_at }));
    },
    insert: async (company: Omit<Company, 'createdAt'>): Promise<Company> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('companies').insert([company]).select();
      if (error) throw error;
      return { ...data[0], createdAt: data[0].created_at };
    }
  },
  employees: {
    fetch: async (): Promise<Employee[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (error) throw error;
      return data.map(e => ({
        id: e.id,
        companyId: e.company_id,
        name: e.name,
        sector: e.sector,
        role: e.role,
        cpf: e.cpf
      }));
    },
    insert: async (emp: Omit<Employee, 'id'>): Promise<Employee> => {
      if (!supabase) throw new Error("Offline");
      const id = emp.id || `EMP-${Math.floor(Math.random() * 10000)}`;
      const { data, error } = await supabase.from('employees').insert([{ 
        id, 
        company_id: emp.companyId, 
        name: emp.name, 
        sector: emp.sector, 
        role: emp.role, 
        cpf: emp.cpf 
      }]).select();
      if (error) throw error;
      return { ...emp, id: data[0].id };
    }
  },
  requests: {
    fetch: async (): Promise<EquipmentRequest[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('equipment_requests').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return data.map(r => ({
        id: r.id,
        requesterId: r.requester_id,
        employeeId: r.employee_id,
        items: r.items,
        itemFulfillments: r.item_fulfillments,
        observation: r.observation,
        status: r.status,
        type: r.type,
        createdAt: r.created_at
      }));
    },
    insert: async (req: Omit<EquipmentRequest, 'createdAt'>): Promise<EquipmentRequest> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('equipment_requests').insert([{
        id: req.id,
        requester_id: req.requesterId,
        employee_id: req.employeeId,
        items: req.items,
        item_fulfillments: req.itemFulfillments,
        observation: req.observation,
        status: req.status,
        type: req.type
      }]).select();
      if (error) throw error;
      return { ...req, createdAt: data[0].created_at };
    },
    update: async (req: EquipmentRequest): Promise<EquipmentRequest> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('equipment_requests').update({
        status: req.status,
        item_fulfillments: req.itemFulfillments,
        observation: req.observation
      }).eq('id', req.id).select();
      if (error) throw error;
      return { ...req, createdAt: data[0].created_at };
    }
  },
  auditSessions: {
    fetch: async (): Promise<AuditSession[]> => {
      if (!supabase) return [];
      const { data, error } = await supabase.from('audit_sessions').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      return data.map(s => ({
        id: s.id,
        sector: s.sector,
        entries: s.entries,
        isFinished: s.is_finished,
        generatedRequestId: s.generated_request_id,
        createdAt: s.created_at
      }));
    },
    insert: async (session: AuditSession): Promise<AuditSession> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('audit_sessions').insert([{
        id: session.id,
        sector: session.sector,
        entries: session.entries,
        is_finished: session.isFinished,
        generated_request_id: session.generatedRequestId
      }]).select();
      if (error) throw error;
      return { ...session, createdAt: data[0].created_at };
    },
    update: async (session: AuditSession): Promise<AuditSession> => {
      if (!supabase) throw new Error("Offline");
      const { data, error } = await supabase.from('audit_sessions').update({
        entries: session.entries,
        is_finished: session.isFinished,
        generated_request_id: session.generatedRequestId
      }).eq('id', session.id).select();
      if (error) throw error;
      return { ...session, createdAt: data[0].created_at };
    }
  }
};

import React, { useState } from 'react';
import { Package, LogIn, Lock, User as UserIcon, AlertCircle, Database, ChevronDown, ChevronUp, Terminal, Copy, Check } from 'lucide-react';
import { UserAccount } from '../types';
import { isSupabaseConfigured } from '../services/supabase';

interface AuthProps {
  onLogin: (user: UserAccount) => void;
  users: UserAccount[];
}

const Auth: React.FC<AuthProps> = ({ onLogin, users }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [showSqlGuide, setShowSqlGuide] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const inputUser = username.toLowerCase();
    const foundUser = users.find(u => u.username.toLowerCase() === inputUser && (u.password === password || (password === 'admin' && !u.password)));

    if (foundUser) onLogin(foundUser);
    else setError('Credenciais inválidas. Verifique usuário e senha.');
  };

  const sqlCode = `-- COPIE E COLE ESTE SCRIPT NO SQL EDITOR DO SUPABASE

-- 1. Tabela de Empresas
CREATE TABLE IF NOT EXISTS companies (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  cnpj TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 2. Tabela de Colaboradores
CREATE TABLE IF NOT EXISTS employees (
  id TEXT PRIMARY KEY,
  company_id TEXT REFERENCES companies(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  sector TEXT,
  role TEXT,
  cpf TEXT
);

-- 3. Tabela de Ativos
CREATE TABLE IF NOT EXISTS assets (
  id TEXT PRIMARY KEY,
  company_id TEXT REFERENCES companies(id) ON DELETE SET NULL,
  type TEXT NOT NULL,
  brand TEXT,
  model TEXT,
  ram TEXT,
  storage TEXT,
  processor TEXT,
  screen_size TEXT,
  observations TEXT,
  photos TEXT[],
  status TEXT NOT NULL,
  assigned_to TEXT REFERENCES employees(id) ON DELETE SET NULL,
  qr_code TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 4. Tabela de Requisições de Equipamentos
CREATE TABLE IF NOT EXISTS equipment_requests (
  id TEXT PRIMARY KEY,
  requester_id TEXT,
  employee_id TEXT REFERENCES employees(id) ON DELETE CASCADE,
  items TEXT[],
  item_fulfillments JSONB,
  observation TEXT,
  status TEXT,
  type TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 5. Tabela de Sessões de Auditoria (Check Semestral)
CREATE TABLE IF NOT EXISTS audit_sessions (
  id TEXT PRIMARY KEY,
  sector TEXT,
  entries JSONB,
  is_finished BOOLEAN DEFAULT FALSE,
  generated_request_id TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Habilitar acesso público inicial (Desativar em produção para maior segurança)
ALTER TABLE companies ENABLE ROW LEVEL SECURITY;
ALTER TABLE employees ENABLE ROW LEVEL SECURITY;
ALTER TABLE assets ENABLE ROW LEVEL SECURITY;
ALTER TABLE equipment_requests ENABLE ROW LEVEL SECURITY;
ALTER TABLE audit_sessions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow public read/write" ON companies FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow public read/write" ON employees FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow public read/write" ON assets FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow public read/write" ON equipment_requests FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "Allow public read/write" ON audit_sessions FOR ALL USING (true) WITH CHECK (true);`;

  const handleCopy = () => {
    navigator.clipboard.writeText(sqlCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md">
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center shadow-xl mb-4 transform -rotate-6">
            <Package className="text-white w-10 h-10" />
          </div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">AssetTrack <span className="text-blue-600">Pro</span></h1>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-xl border border-slate-100 p-8">
          <form onSubmit={handleSubmit} className="space-y-5">
            <div className="space-y-1.5">
              <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                <UserIcon className="w-4 h-4 text-slate-400" /> Usuário
              </label>
              <input type="text" required className="w-full p-3.5 rounded-2xl border border-slate-200 outline-none" placeholder="admin" value={username} onChange={(e) => setUsername(e.target.value)} />
            </div>
            <div className="space-y-1.5">
              <label className="text-sm font-bold text-slate-700 flex items-center gap-2">
                <Lock className="w-4 h-4 text-slate-400" /> Senha
              </label>
              <input type="password" required className="w-full p-3.5 rounded-2xl border border-slate-200 outline-none" placeholder="admin" value={password} onChange={(e) => setPassword(e.target.value)} />
            </div>
            <button type="submit" className="w-full bg-blue-600 text-white font-bold py-4 rounded-2xl shadow-lg transition-all active:scale-95">Acessar Sistema</button>
          </form>

          <div className="mt-10 pt-6 border-t border-slate-100">
            <button 
              onClick={() => setShowSqlGuide(!showSqlGuide)}
              className={`w-full flex items-center justify-between p-4 rounded-2xl text-left transition-all ${isSupabaseConfigured ? 'bg-emerald-50 text-emerald-700' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}
            >
              <div className="flex items-center gap-3">
                <Database className="w-5 h-5" />
                <span className="text-xs font-black uppercase tracking-widest">Script SQL para o Banco</span>
              </div>
              {showSqlGuide ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
            </button>

            {showSqlGuide && (
              <div className="mt-4 space-y-4 animate-in fade-in slide-in-from-top-2">
                <div className="p-4 bg-slate-900 rounded-2xl relative group">
                   <div className="flex items-center justify-between text-blue-400 mb-3">
                      <div className="flex items-center gap-2">
                        <Terminal className="w-4 h-4" />
                        <span className="text-[10px] font-black uppercase">Executar no Supabase SQL Editor</span>
                      </div>
                      <button 
                        onClick={handleCopy}
                        className="p-1.5 bg-white/10 hover:bg-white/20 rounded-lg transition-colors flex items-center gap-1.5"
                      >
                        {copied ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
                        <span className="text-[9px] font-bold uppercase">{copied ? 'Copiado!' : 'Copiar'}</span>
                      </button>
                   </div>
                   <pre className="text-[9px] text-slate-300 font-mono overflow-x-auto whitespace-pre-wrap leading-relaxed max-h-60 custom-scrollbar">
                     {sqlCode}
                   </pre>
                </div>
                <div className="p-3 bg-blue-50 border border-blue-100 rounded-xl">
                   <p className="text-[10px] text-blue-700 font-bold leading-tight">
                     Dica: Clique em "Copiar" e cole no menu <b>SQL Editor</b> do Supabase para criar as tabelas instantaneamente.
                   </p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AssetManager from './components/AssetManager';
import EmployeeManager from './components/EmployeeManager';
import RequestsManager from './components/RequestsManager';
import CompanyManager from './components/CompanyManager';
import MaintenanceManager from './components/MaintenanceManager';
import PurchaseOrderManager from './components/PurchaseOrderManager';
import PrintManager from './components/PrintManager';
import UserManager from './components/UserManager';
import InventoryCheckManager from './components/InventoryCheckManager';
import Auth from './components/Auth';
import { MOCK_USERS, MOCK_ASSETS, MOCK_COMPANIES, MOCK_EMPLOYEES } from './constants';
import { Asset, Employee, EquipmentRequest, UserAccount, Company, AuditSession } from './types';
import { db, isSupabaseConfigured } from './services/supabase';
import { Cloud, CloudOff } from 'lucide-react';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState<UserAccount | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isLoading, setIsLoading] = useState(false);

  const [companies, setCompanies] = useState<Company[]>(MOCK_COMPANIES);
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [employees, setEmployees] = useState<Employee[]>(MOCK_EMPLOYEES);
  const [requests, setRequests] = useState<EquipmentRequest[]>([]);
  const [auditSessions, setAuditSessions] = useState<AuditSession[]>([]);

  useEffect(() => {
    const loadData = async () => {
      if (!isAuthenticated || !isSupabaseConfigured) return;

      try {
        setIsLoading(true);
        const [a, c, e, r, s] = await Promise.all([
          db.assets.fetch(),
          db.companies.fetch(),
          db.employees.fetch(),
          db.requests.fetch(),
          db.auditSessions.fetch()
        ]);

        if (c.length > 0) setCompanies(c);
        if (a.length > 0) setAssets(a);
        if (e.length > 0) setEmployees(e);
        if (r.length > 0) setRequests(r);
        if (s.length > 0) setAuditSessions(s);
      } catch (err) {
        console.warn("Falha na sincronização Cloud. Usando dados locais.", err);
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, [isAuthenticated]);

  const handleLogin = (user: UserAccount) => {
    setCurrentUser(user);
    setIsAuthenticated(true);
    if (user.modules.length > 0) setActiveTab(user.modules[0]);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleAddAsset = async (assetData: any) => {
    const id = assetData.id || `AST-${Math.floor(Math.random() * 9000) + 1000}`;
    const newAsset = { ...assetData, id, qrCode: `QR-${id}` };

    if (isSupabaseConfigured) {
      try {
        const saved = await db.assets.insert(newAsset);
        setAssets([saved, ...assets]);
      } catch (e) { alert("Erro ao salvar no banco."); }
    } else {
      setAssets([{ ...newAsset, createdAt: new Date().toISOString() } as Asset, ...assets]);
    }
  };

  const handleUpdateAsset = async (updated: Asset) => {
    if (isSupabaseConfigured) {
      try {
        const saved = await db.assets.update(updated.id, updated);
        setAssets(assets.map(a => a.id === updated.id ? saved : a));
      } catch (e) { alert("Erro ao atualizar no banco."); }
    } else {
      setAssets(assets.map(a => a.id === updated.id ? updated : a));
    }
  };

  const handleAddRequest = async (reqData: any) => {
    const id = `REQ-${Math.floor(Math.random() * 9000) + 1000}`;
    const newReq = { ...reqData, id, status: 'Pendente' };

    if (isSupabaseConfigured) {
      try {
        const saved = await db.requests.insert(newReq);
        setRequests([saved, ...requests]);
      } catch (e) { alert("Erro ao criar requisição."); }
    } else {
      setRequests([{ ...newReq, createdAt: new Date().toISOString() } as EquipmentRequest, ...requests]);
    }
  };

  const handleUpdateRequest = async (req: EquipmentRequest) => {
    if (isSupabaseConfigured) {
      try {
        const saved = await db.requests.update(req);
        setRequests(requests.map(r => r.id === req.id ? saved : r));
      } catch (e) { alert("Erro ao atualizar requisição."); }
    } else {
      setRequests(requests.map(r => r.id === req.id ? req : r));
    }
  };

  const renderContent = () => {
    if (isLoading) return (
      <div className="flex flex-col items-center justify-center p-20">
         <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
         <p className="mt-4 text-blue-600 font-bold uppercase tracking-widest text-xs">Sincronizando Cloud...</p>
      </div>
    );

    switch (activeTab) {
      case 'dashboard': return <Dashboard assets={assets} requests={requests} employees={employees} />;
      case 'companies': return <CompanyManager companies={companies} assets={assets} onAddCompany={async (c) => { if(isSupabaseConfigured) { const s = await db.companies.insert(c); setCompanies([...companies, s]); } else setCompanies([...companies, {...c, id: Math.random().toString(), createdAt: ''}])}} onUpdateCompany={()=>{}} onRemoveCompany={()=>{}} />;
      case 'assets': return <AssetManager assets={assets} employees={employees} companies={companies} onAdd={handleAddAsset} onUpdate={handleUpdateAsset} onRemove={async (id) => { if(isSupabaseConfigured) await db.assets.delete(id); setAssets(assets.filter(a => a.id !== id)); }} />;
      case 'employees': return <EmployeeManager employees={employees} onAdd={async (e) => { if(isSupabaseConfigured) { const s = await db.employees.insert(e); setEmployees([...employees, s]); } else setEmployees([...employees, {...e, id: Math.random().toString()}])}} />;
      case 'requests': return <RequestsManager requests={requests} employees={employees} assets={assets} onAddRequest={handleAddRequest} onUpdateRequest={handleUpdateRequest} onUpdateStatus={(id, status) => { const req = requests.find(r => r.id === id); if(req) handleUpdateRequest({...req, status}); }} />;
      case 'inventory-check': return <InventoryCheckManager assets={assets} employees={employees} auditSessions={auditSessions} onAddAuditSession={async (s) => { if(isSupabaseConfigured) { const saved = await db.auditSessions.insert(s); setAuditSessions([saved, ...auditSessions]); } else setAuditSessions([s, ...auditSessions]); }} onUpdateAuditSession={async (s) => { if(isSupabaseConfigured) { const saved = await db.auditSessions.update(s); setAuditSessions(auditSessions.map(old => old.id === s.id ? saved : old)); } else setAuditSessions(auditSessions.map(old => old.id === s.id ? s : old)); }} onGenerateDivergenceRequest={(sector, assetIds) => handleAddRequest({ requesterId: currentUser?.id, employeeId: employees.find(e => e.sector === sector)?.id || '', items: assets.filter(a => assetIds.includes(a.id)).map(a => a.type), type: 'Divergencia', observation: `Divergência de auditoria no setor ${sector}` })} />;
      case 'maintenance': return <MaintenanceManager assets={assets} employees={employees} companies={companies} onUpdateAsset={handleUpdateAsset} />;
      case 'purchase-orders': return <PurchaseOrderManager requests={requests} employees={employees} onUpdateRequest={handleUpdateRequest} onAssetCreated={handleAddAsset} />;
      case 'printing': return <PrintManager assets={assets} />;
      case 'user-management': return <UserManager users={MOCK_USERS} onAddUser={()=>{}} onUpdateUser={()=>{}} onRemoveUser={()=>{}} />;
      default: return <div className="p-20 text-center text-slate-400 font-bold uppercase">Módulo Cloud</div>;
    }
  };

  if (!isAuthenticated || !currentUser) return <Auth onLogin={handleLogin} users={MOCK_USERS} />;

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} requests={requests}>
      <div className="mb-4 flex items-center gap-2">
        {isSupabaseConfigured ? (
          <div className="flex items-center gap-2 bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-emerald-100">
            <Cloud className="w-3 h-3" /> Cloud Conectado
          </div>
        ) : (
          <div className="flex items-center gap-2 bg-amber-50 text-amber-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-100">
            <CloudOff className="w-3 h-3" /> Modo Offline (Local)
          </div>
        )}
      </div>
      {renderContent()}
    </Layout>
  );
};

export default App;

